import type { Article } from '../../../common/types/law.types';

export const ARTICLES_CONST_MENDOZA: Article[] = [
  { id: 'const-mendoza-art-1', lawId: 'const-mendoza', number: '1', title: '', originalText: `La Provincia de Mendoza es parte integrante e inseparable de la Nación Argentina y la Constitución Nacional es su Ley Suprema. Su autonomía es de la esencia de su gobierno y lo organiza bajo la forma republicana representativa, manteniendo en su integridad todos los poderes no conferidos por la Constitución Federal al Gobierno de la Nación. Sus yacimientos de hidrocarburos líquidos y gaseosos, como así también toda otra fuente natural de energía sólida, líquida o gaseosa, situada en subsuelo y suelo, pertenecen al patrimonio exclusivo, inalienable e imprescriptible del Estado Provincial. Su explotación debe ser preservada en beneficio de las generaciones actuales y futuras. La Provincia podrá acordar con otras y con el Gobierno Nacional sistemas regionales o federales de explotación.`, currentText: `La Provincia de Mendoza es parte integrante e inseparable de la Nación Argentina y la Constitución Nacional es su Ley Suprema. Su autonomía es de la esencia de su gobierno y lo organiza bajo la forma republicana representativa, manteniendo en su integridad todos los poderes no conferidos por la Constitución Federal al Gobierno de la Nación. Sus yacimientos de hidrocarburos líquidos y gaseosos, como así también toda otra fuente natural de energía sólida, líquida o gaseosa, situada en subsuelo y suelo, pertenecen al patrimonio exclusivo, inalienable e imprescriptible del Estado Provincial. Su explotación debe ser preservada en beneficio de las generaciones actuales y futuras. La Provincia podrá acordar con otras y con el Gobierno Nacional sistemas regionales o federales de explotación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-2', lawId: 'const-mendoza', number: '2', title: '', originalText: `La ciudad de Mendoza es la capital de la Provincia.`, currentText: `La ciudad de Mendoza es la capital de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-3', lawId: 'const-mendoza', number: '3', title: '', originalText: `Toda ley que modifique la jurisdicción pública actual de la Provincia, sobre parte de su territorio, ya sea por cesión, anexión o de cualquier otra manera, deberá ser sancionada por dos tercios de votos del número de miembros que componen cada Cámara.`, currentText: `Toda ley que modifique la jurisdicción pública actual de la Provincia, sobre parte de su territorio, ya sea por cesión, anexión o de cualquier otra manera, deberá ser sancionada por dos tercios de votos del número de miembros que componen cada Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-4', lawId: 'const-mendoza', number: '4', title: '', originalText: `La soberanía reside esencialmente en el pueblo, del cual emanan todos los poderes.`, currentText: `La soberanía reside esencialmente en el pueblo, del cual emanan todos los poderes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-5', lawId: 'const-mendoza', number: '5', title: '', originalText: `Un registro del estado civil de las personas será uniformemente llevado en toda la Provincia, por las autoridades civiles, sin distinción de creencias religiosas.`, currentText: `Un registro del estado civil de las personas será uniformemente llevado en toda la Provincia, por las autoridades civiles, sin distinción de creencias religiosas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-6', lawId: 'const-mendoza', number: '6', title: '', originalText: `Es inviolable en el territorio de la Provincia el derecho que todo hombre tiene de rendir culto a Dios o profesar cualquier religión, libre y públicamente, según los dictados de su conciencia, sin otras restricciones que las que prescriben la moral y el orden público.`, currentText: `Es inviolable en el territorio de la Provincia el derecho que todo hombre tiene de rendir culto a Dios o profesar cualquier religión, libre y públicamente, según los dictados de su conciencia, sin otras restricciones que las que prescriben la moral y el orden público.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-7', lawId: 'const-mendoza', number: '7', title: '', originalText: `Todos los habitantes de la Provincia son iguales ante la ley y ésta debe ser una misma para todos y tener una acción y fuerza uniformes.`, currentText: `Todos los habitantes de la Provincia son iguales ante la ley y ésta debe ser una misma para todos y tener una acción y fuerza uniformes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-8', lawId: 'const-mendoza', number: '8', title: '', originalText: `Todos los habitantes de la Provincia son, por su naturaleza, libres e independientes y tienen derecho perfecto de defender su vida, libertad, reputación, seguridad y propiedad y de ser protegidos en estos goces. Nadie puede ser privado de ellos sino por vía de penalidad, con arreglo a ley anterior al hecho del proceso y previa sentencia legal de juez competente.`, currentText: `Todos los habitantes de la Provincia son, por su naturaleza, libres e independientes y tienen derecho perfecto de defender su vida, libertad, reputación, seguridad y propiedad y de ser protegidos en estos goces. Nadie puede ser privado de ellos sino por vía de penalidad, con arreglo a ley anterior al hecho del proceso y previa sentencia legal de juez competente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-9', lawId: 'const-mendoza', number: '9', title: '', originalText: `El pueblo no delibera ni gobierna sino por medio de sus representantes y autoridades establecidas con arreglo a esta Constitución.`, currentText: `El pueblo no delibera ni gobierna sino por medio de sus representantes y autoridades establecidas con arreglo a esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-10', lawId: 'const-mendoza', number: '10', title: '', originalText: `Todos los habitantes de la Provincia tienen el derecho de reunirse para tratar asuntos públicos o privados con tal que no turben el orden público; así como el de peticionar individual o colectivamente, ante todas y cada una de las autoridades, sea para solicitar gracia o justicia, sea para instruir a sus representantes o para pedir la reparación de agravios, pero ninguna reunión podrá atribuirse la representación ni los derechos del pueblo. El derecho de petición no podrá ejercerse colectivamente por ninguna clase de fuerza armada, ni individualmente por los que formen parte de ella, sino con arreglo a las leyes. Cualquier disposición adoptada por las autoridades en presencia o a requisición de fuerza armada o de una reunión sediciosa que se atribuya los derechos del pueblo, es nula y jamás podrá tener efecto.`, currentText: `Todos los habitantes de la Provincia tienen el derecho de reunirse para tratar asuntos públicos o privados con tal que no turben el orden público; así como el de peticionar individual o colectivamente, ante todas y cada una de las autoridades, sea para solicitar gracia o justicia, sea para instruir a sus representantes o para pedir la reparación de agravios, pero ninguna reunión podrá atribuirse la representación ni los derechos del pueblo. El derecho de petición no podrá ejercerse colectivamente por ninguna clase de fuerza armada, ni individualmente por los que formen parte de ella, sino con arreglo a las leyes. Cualquier disposición adoptada por las autoridades en presencia o a requisición de fuerza armada o de una reunión sediciosa que se atribuya los derechos del pueblo, es nula y jamás podrá tener efecto.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-11', lawId: 'const-mendoza', number: '11', title: '', originalText: `Queda asegurado a todos los habitantes de la Provincia el derecho de emitir libremente sus ideas y opiniones de palabra o por escrito, valiéndose de la imprenta u otro procedimiento semejante, sin otra responsabilidad que las que resulte del abuso que pueda hacerse de este derecho, por delito o contravención, y ninguna ley, ni disposición se dictarán estableciendo a su respecto medidas preventivas, o restringiéndolo o limitándolo de manera alguna. Tampoco podrá dictarse ley ni disposición que exija en el director o editor, otras condiciones que el pleno goce de su capacidad civil. En los juicios a que diere lugar el ejercicio de la libertad de la prensa, se admitirá como descargo la prueba de los hechos denunciados, siempre que se trate de la conducta oficial de los funcionarios o empleados públicos y en general en caso de calumnia. A los tribunales ordinarios les corresponderá exclusivamente entender en esta clase de juicios.`, currentText: `Queda asegurado a todos los habitantes de la Provincia el derecho de emitir libremente sus ideas y opiniones de palabra o por escrito, valiéndose de la imprenta u otro procedimiento semejante, sin otra responsabilidad que las que resulte del abuso que pueda hacerse de este derecho, por delito o contravención, y ninguna ley, ni disposición se dictarán estableciendo a su respecto medidas preventivas, o restringiéndolo o limitándolo de manera alguna. Tampoco podrá dictarse ley ni disposición que exija en el director o editor, otras condiciones que el pleno goce de su capacidad civil. En los juicios a que diere lugar el ejercicio de la libertad de la prensa, se admitirá como descargo la prueba de los hechos denunciados, siempre que se trate de la conducta oficial de los funcionarios o empleados públicos y en general en caso de calumnia. A los tribunales ordinarios les corresponderá exclusivamente entender en esta clase de juicios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-12', lawId: 'const-mendoza', number: '12', title: '', originalText: `El gobierno de la Provincia será dividido en tres poderes distintos: Legislativo, Ejecutivo y Judicial. Ninguno de éstos podrá arrogarse, bajo pena de nulidad, facultades que no le estén deferidas por esta Constitución, ni delegar las que le correspondan.`, currentText: `El gobierno de la Provincia será dividido en tres poderes distintos: Legislativo, Ejecutivo y Judicial. Ninguno de éstos podrá arrogarse, bajo pena de nulidad, facultades que no le estén deferidas por esta Constitución, ni delegar las que le correspondan.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-13', lawId: 'const-mendoza', number: '13', title: '', originalText: `Nadie podrá acumular dos o más empleos o funciones públicas rentados, aun cuando el uno fuera provincial y el otro nacional. En cuanto a los gratuitos, profesionales o técnicos, los del profesorado y comisiones eventuales, la ley determinará los que sean incompatibles.`, currentText: `Nadie podrá acumular dos o más empleos o funciones públicas rentados, aun cuando el uno fuera provincial y el otro nacional. En cuanto a los gratuitos, profesionales o técnicos, los del profesorado y comisiones eventuales, la ley determinará los que sean incompatibles.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-14', lawId: 'const-mendoza', number: '14', title: '', originalText: `El domicilio es inviolable y sólo podrá ser allanado en virtud de orden escrita de juez competente o de autoridad sanitaria o municipal por razón de salubridad pública. La ley determinará los casos y forma de practicarse el allanamiento. La orden deberá ser motivada y determinada, haciéndose responsable en caso contrario, tanto al que la expida, como al que la ejecute.`, currentText: `El domicilio es inviolable y sólo podrá ser allanado en virtud de orden escrita de juez competente o de autoridad sanitaria o municipal por razón de salubridad pública. La ley determinará los casos y forma de practicarse el allanamiento. La orden deberá ser motivada y determinada, haciéndose responsable en caso contrario, tanto al que la expida, como al que la ejecute.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-15', lawId: 'const-mendoza', number: '15', title: '', originalText: `La correspondencia epistolar, telegráfica o por otro medio de comunicación análogo, es inviolable y no puede ser ocupada o intervenida sino por autoridad judicial competente y en los casos designados por las leyes.`, currentText: `La correspondencia epistolar, telegráfica o por otro medio de comunicación análogo, es inviolable y no puede ser ocupada o intervenida sino por autoridad judicial competente y en los casos designados por las leyes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-16', lawId: 'const-mendoza', number: '16', title: '', originalText: `La propiedad es inviolable, y ningún habitante de la Provincia puede ser privado ni desposeído de ella, sino en virtud de sentencia fundada en ley, o por causa de utilidad pública, calificada en cada caso por la Legislatura y previa indemnización.`, currentText: `La propiedad es inviolable, y ningún habitante de la Provincia puede ser privado ni desposeído de ella, sino en virtud de sentencia fundada en ley, o por causa de utilidad pública, calificada en cada caso por la Legislatura y previa indemnización.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-17', lawId: 'const-mendoza', number: '17', title: '', originalText: `Nadie puede ser detenido sin que preceda indagación sumaria que produzca semiplena prueba o indicio vehemente de un hecho que merezca pena corporal, salvo el caso infraganti, en que todo delincuente puede ser detenido por cualquier persona y conducido inmediatamente a presencia de su juez o de la autoridad policial próxima, ni podrá ser constituido en prisión sin orden escrita de juez competente.`, currentText: `Nadie puede ser detenido sin que preceda indagación sumaria que produzca semiplena prueba o indicio vehemente de un hecho que merezca pena corporal, salvo el caso infraganti, en que todo delincuente puede ser detenido por cualquier persona y conducido inmediatamente a presencia de su juez o de la autoridad policial próxima, ni podrá ser constituido en prisión sin orden escrita de juez competente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-18', lawId: 'const-mendoza', number: '18', title: '', originalText: `Toda orden de pesquisa, detención de una o más personas, o embargo de propiedades, deberá especificar las personas u objetos de pesquisa o embargo, individualizando el lugar que debe ser registrado y no se expedirá mandato de esa clase sino por hecho punible apoyado en juramento o afirmación sin cuyos requisitos, la orden o mandato no será exequible.`, currentText: `Toda orden de pesquisa, detención de una o más personas, o embargo de propiedades, deberá especificar las personas u objetos de pesquisa o embargo, individualizando el lugar que debe ser registrado y no se expedirá mandato de esa clase sino por hecho punible apoyado en juramento o afirmación sin cuyos requisitos, la orden o mandato no será exequible.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-19', lawId: 'const-mendoza', number: '19', title: '', originalText: `Todo aprehendido será notificado de la causa de su detención dentro de veinticuatro horas y desde entonces, no se le podrá tener incomunicado más de tres días de un modo absoluto.`, currentText: `Todo aprehendido será notificado de la causa de su detención dentro de veinticuatro horas y desde entonces, no se le podrá tener incomunicado más de tres días de un modo absoluto.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-20', lawId: 'const-mendoza', number: '20', title: '', originalText: `Todo alcaide o guardián de presos, al recibirse de alguno, deberá bajo su responsabilidad, exigir y conservar en su poder la orden motivada de su prisión. Incumbe exigir la misma orden, bajo la propia responsabilidad, al ejecutor del arresto o prisión.`, currentText: `Todo alcaide o guardián de presos, al recibirse de alguno, deberá bajo su responsabilidad, exigir y conservar en su poder la orden motivada de su prisión. Incumbe exigir la misma orden, bajo la propia responsabilidad, al ejecutor del arresto o prisión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-21', lawId: 'const-mendoza', number: '21', title: '', originalText: `Toda persona detenida podrá pedir por sí, u otra en su nombre, que se le haga comparecer ante el juez más inmediato, y expedido que sea el auto por autoridad competente, no podrá ser detenida contra su voluntad, si pasadas las veinticuatro horas no se le hubiese notificado por juez igualmente competente, la causa de su detención. Todo juez, aunque lo sea de un tribunal colegiado, a quien se le hiciera esta petición, o se le reclamase la garantía del artículo 19, deberá proceder en el término de veinticuatro horas, contadas desde su presentación, con cargo auténtico, bajo multa de mil pesos nacionales. Proveída la petición, el funcionario que retuviese al detenido o dejase de cumplir dentro del término señalado por el juez, el requerimiento de éste, incurrirá en la misma multa, sin perjuicio de hacerse efectivo el auto.`, currentText: `Toda persona detenida podrá pedir por sí, u otra en su nombre, que se le haga comparecer ante el juez más inmediato, y expedido que sea el auto por autoridad competente, no podrá ser detenida contra su voluntad, si pasadas las veinticuatro horas no se le hubiese notificado por juez igualmente competente, la causa de su detención. Todo juez, aunque lo sea de un tribunal colegiado, a quien se le hiciera esta petición, o se le reclamase la garantía del artículo 19, deberá proceder en el término de veinticuatro horas, contadas desde su presentación, con cargo auténtico, bajo multa de mil pesos nacionales. Proveída la petición, el funcionario que retuviese al detenido o dejase de cumplir dentro del término señalado por el juez, el requerimiento de éste, incurrirá en la misma multa, sin perjuicio de hacerse efectivo el auto.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-22', lawId: 'const-mendoza', number: '22', title: '', originalText: `Cuando el hecho que motivó la detención de un procesado, tenga sólo pena pecuniaria o corporal cuyo promedio no exceda de dos años de prisión, o una y otra conjuntamente, podrá decretarse la libertad provisoria, salvo limitaciones que la ley establezca para los casos de reincidencia o reiteración y siempre que presente algunas de las cauciones que ella determine.`, currentText: `Cuando el hecho que motivó la detención de un procesado, tenga sólo pena pecuniaria o corporal cuyo promedio no exceda de dos años de prisión, o una y otra conjuntamente, podrá decretarse la libertad provisoria, salvo limitaciones que la ley establezca para los casos de reincidencia o reiteración y siempre que presente algunas de las cauciones que ella determine.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-23', lawId: 'const-mendoza', number: '23', title: '', originalText: `Las cárceles son hechas para seguridad y no para mortificación de los detenidos, y tanto éstas como las colonias penales, serán reglamentadas de manera que constituyan centros de trabajo y moralización. Todo rigor innecesario hace responsables a las autoridades que lo ejerzan.`, currentText: `Las cárceles son hechas para seguridad y no para mortificación de los detenidos, y tanto éstas como las colonias penales, serán reglamentadas de manera que constituyan centros de trabajo y moralización. Todo rigor innecesario hace responsables a las autoridades que lo ejerzan.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-24', lawId: 'const-mendoza', number: '24', title: '', originalText: `Ninguna detención o arresto se hará en cárceles de penados, sino en locales destinados especialmente a ese objeto. Los presos no serán sacados de la Provincia para cumplir sus condenas en otras cárceles, ni se admitirán en las suyas, presos de fuera de ella, salvo las excepciones que establezca la ley.`, currentText: `Ninguna detención o arresto se hará en cárceles de penados, sino en locales destinados especialmente a ese objeto. Los presos no serán sacados de la Provincia para cumplir sus condenas en otras cárceles, ni se admitirán en las suyas, presos de fuera de ella, salvo las excepciones que establezca la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-25', lawId: 'const-mendoza', number: '25', title: '', originalText: `Nadie puede ser condenado sin juicio previo fundado en ley anterior al hecho por que se le procesa, ni juzgado por comisiones o tribunales especiales, cualquiera que sea la denominación que se les dé.`, currentText: `Nadie puede ser condenado sin juicio previo fundado en ley anterior al hecho por que se le procesa, ni juzgado por comisiones o tribunales especiales, cualquiera que sea la denominación que se les dé.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-26', lawId: 'const-mendoza', number: '26', title: '', originalText: `Nadie puede ser obligado a declarar ni a prestar juramento contra sí mismo en materia criminal, ni encausado dos veces por un mismo hecho delictuoso. La sentencia en causa criminal debe ser definitiva, absolviendo o condenando al acusado.`, currentText: `Nadie puede ser obligado a declarar ni a prestar juramento contra sí mismo en materia criminal, ni encausado dos veces por un mismo hecho delictuoso. La sentencia en causa criminal debe ser definitiva, absolviendo o condenando al acusado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-27', lawId: 'const-mendoza', number: '27', title: '', originalText: `Ninguna persona puede ser privada de su libertad por deuda, salvo el caso de delito.`, currentText: `Ninguna persona puede ser privada de su libertad por deuda, salvo el caso de delito.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-28', lawId: 'const-mendoza', number: '28', title: '', originalText: `Ningún reclutamiento forzoso podrá hacerse en la Provincia a objeto del servicio policial o de guarnición, el cual será desempeñado por alistados o contratados a expensas del Tesoro Provincial.`, currentText: `Ningún reclutamiento forzoso podrá hacerse en la Provincia a objeto del servicio policial o de guarnición, el cual será desempeñado por alistados o contratados a expensas del Tesoro Provincial.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-29', lawId: 'const-mendoza', number: '29', title: '', originalText: `El Poder Legislativo no podrá dictar leyes que priven de derechos adquiridos, o alteren las obligaciones de los contratos.`, currentText: `El Poder Legislativo no podrá dictar leyes que priven de derechos adquiridos, o alteren las obligaciones de los contratos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-30', lawId: 'const-mendoza', number: '30', title: '', originalText: `Todos los argentinos son admisibles a los empleos públicos de la Provincia, sin otras condiciones que su buena conducta y capacidad, en todos aquellos casos en que esta Constitución o la ley no exijan calidades especiales. La remoción del empleado deberá obedecer a causa justificada, y se dictará una ley especial que rija en materia de empleo, su duración, estabilidad, retribución y promoción o ascenso.`, currentText: `Todos los argentinos son admisibles a los empleos públicos de la Provincia, sin otras condiciones que su buena conducta y capacidad, en todos aquellos casos en que esta Constitución o la ley no exijan calidades especiales. La remoción del empleado deberá obedecer a causa justificada, y se dictará una ley especial que rija en materia de empleo, su duración, estabilidad, retribución y promoción o ascenso.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-31', lawId: 'const-mendoza', number: '31', title: '', originalText: `Los extranjeros gozarán en el territorio de la Provincia, de todos los derechos civiles del ciudadano y de los que la Constitución y las leyes les acuerden.`, currentText: `Los extranjeros gozarán en el territorio de la Provincia, de todos los derechos civiles del ciudadano y de los que la Constitución y las leyes les acuerden.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-32', lawId: 'const-mendoza', number: '32', title: '', originalText: `La igualdad es la base del impuesto y de las cargas públicas.`, currentText: `La igualdad es la base del impuesto y de las cargas públicas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-33', lawId: 'const-mendoza', number: '33', title: '', originalText: `Esta Constitución garantiza a todos los habitantes de la Provincia, la libertad de trabajo, industria y comercio, siempre que no se opongan a la moral, seguridad, salubridad pública, las leyes del país o derechos de tercero. La Legislatura no podrá establecer impuestos que graven en cualquier forma, los artículos de primera necesidad, salvo cuando ellos respondiesen a exigencias de la salubridad pública.`, currentText: `Esta Constitución garantiza a todos los habitantes de la Provincia, la libertad de trabajo, industria y comercio, siempre que no se opongan a la moral, seguridad, salubridad pública, las leyes del país o derechos de tercero. La Legislatura no podrá establecer impuestos que graven en cualquier forma, los artículos de primera necesidad, salvo cuando ellos respondiesen a exigencias de la salubridad pública.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-34', lawId: 'const-mendoza', number: '34', title: '', originalText: `Ningún habitante de la Provincia estará obligado a hacer lo que la ley no manda, ni será privado de lo que ella no prohíbe. Las acciones privadas de los hombres que de ningún modo ofendan a la moral y al orden público, ni perjudiquen a terceros están exentas de la autoridad de los magistrados.`, currentText: `Ningún habitante de la Provincia estará obligado a hacer lo que la ley no manda, ni será privado de lo que ella no prohíbe. Las acciones privadas de los hombres que de ningún modo ofendan a la moral y al orden público, ni perjudiquen a terceros están exentas de la autoridad de los magistrados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-35', lawId: 'const-mendoza', number: '35', title: '', originalText: `Todos los habitantes de la Provincia, podrán fundar y mantener establecimientos de enseñanza sin previa licencia, salvo la inspección de la autoridad competente, por razones de higiene, moralidad y orden público.`, currentText: `Todos los habitantes de la Provincia, podrán fundar y mantener establecimientos de enseñanza sin previa licencia, salvo la inspección de la autoridad competente, por razones de higiene, moralidad y orden público.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-36', lawId: 'const-mendoza', number: '36', title: '', originalText: `Los actos oficiales de todas las reparticiones de la administración, en especial los que se relacionan con la percepción e inversión de la renta, deberán publicarse en la forma y modo que la ley determine.`, currentText: `Los actos oficiales de todas las reparticiones de la administración, en especial los que se relacionan con la percepción e inversión de la renta, deberán publicarse en la forma y modo que la ley determine.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-37', lawId: 'const-mendoza', number: '37', title: '', originalText: `Toda enajenación de bienes del fisco, compras y demás contratos susceptibles de licitación, se harán precisamente en esa forma y de un modo público, bajo pena de nulidad, sin perjuicio de la responsabilidad por defraudación si la hubiere, salvo las excepciones que la ley determine en cuanto se refiere a la licitación.`, currentText: `Toda enajenación de bienes del fisco, compras y demás contratos susceptibles de licitación, se harán precisamente en esa forma y de un modo público, bajo pena de nulidad, sin perjuicio de la responsabilidad por defraudación si la hubiere, salvo las excepciones que la ley determine en cuanto se refiere a la licitación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-38', lawId: 'const-mendoza', number: '38', title: '', originalText: `Todos los empleados públicos de la Provincia, no sujetos a juicio político, son enjuiciables antes los tribunales ordinarios, por delitos que cometan en el desempeño de sus funciones, sin necesidad de autorización previa, cualquiera que sea el delito que cometieren y sin que puedan excusarse de contestar o declinar jurisdicción, alegando órdenes o aprobación superior.`, currentText: `Todos los empleados públicos de la Provincia, no sujetos a juicio político, son enjuiciables antes los tribunales ordinarios, por delitos que cometan en el desempeño de sus funciones, sin necesidad de autorización previa, cualquiera que sea el delito que cometieren y sin que puedan excusarse de contestar o declinar jurisdicción, alegando órdenes o aprobación superior.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-39', lawId: 'const-mendoza', number: '39', title: '', originalText: `No podrá dictarse ley ni disposición que tenga por objeto acordar remuneración extraordinaria a ningún funcionario o empleado de los poderes públicos, mientras lo sean, por servicios hechos o que les encarguen en el ejercicio de sus funciones, o por comisiones especiales o extraordinarias.`, currentText: `No podrá dictarse ley ni disposición que tenga por objeto acordar remuneración extraordinaria a ningún funcionario o empleado de los poderes públicos, mientras lo sean, por servicios hechos o que les encarguen en el ejercicio de sus funciones, o por comisiones especiales o extraordinarias.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-40', lawId: 'const-mendoza', number: '40', title: '', originalText: `El Estado como persona jurídica, podrá ser demandado ante la justicia ordinaria, sin necesidad de autorización previa del Poder Legislativo y sin que el juicio deba gozar de privilegio alguno. Sin embargo, siendo condenado al pago de alguna deuda, no podrá ser ejecutado en la forma ordinaria, ni embargados sus bienes, salvo el caso de hallarse asegurado aquella con prenda, hipoteca o anticresis, en que podrá llevarse ejecución sobre los bienes que constituyan la garantía. En los demás casos corresponde a la Legislatura arbitrar el modo y forma de verificar el pago. Los trámites de esta decisión, no excederán de tres meses, so pena de quedar sin efecto, por la sola expiración del término, la excepción concedida por este artículo.`, currentText: `El Estado como persona jurídica, podrá ser demandado ante la justicia ordinaria, sin necesidad de autorización previa del Poder Legislativo y sin que el juicio deba gozar de privilegio alguno. Sin embargo, siendo condenado al pago de alguna deuda, no podrá ser ejecutado en la forma ordinaria, ni embargados sus bienes, salvo el caso de hallarse asegurado aquella con prenda, hipoteca o anticresis, en que podrá llevarse ejecución sobre los bienes que constituyan la garantía. En los demás casos corresponde a la Legislatura arbitrar el modo y forma de verificar el pago. Los trámites de esta decisión, no excederán de tres meses, so pena de quedar sin efecto, por la sola expiración del término, la excepción concedida por este artículo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-41', lawId: 'const-mendoza', number: '41', title: '', originalText: `No podrá autorizarse empréstito alguno sobre el crédito general de la Provincia, ni emisión de fondos públicos, sino por ley sancionada por dos tercios de votos de los miembros presentes de cada Cámara. Toda ley que sancione empréstito deberá especificar los recursos especiales con que deba hacerse el servicio de la deuda y su amortización. No podrán aplicarse los recursos que se obtenga por empréstito, sino a los objetos determinados, que debe especificar la ley que lo autorice, bajo responsabilidad de la autoridad que los invierta o destine a otros objetos.`, currentText: `No podrá autorizarse empréstito alguno sobre el crédito general de la Provincia, ni emisión de fondos públicos, sino por ley sancionada por dos tercios de votos de los miembros presentes de cada Cámara. Toda ley que sancione empréstito deberá especificar los recursos especiales con que deba hacerse el servicio de la deuda y su amortización. No podrán aplicarse los recursos que se obtenga por empréstito, sino a los objetos determinados, que debe especificar la ley que lo autorice, bajo responsabilidad de la autoridad que los invierta o destine a otros objetos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-42', lawId: 'const-mendoza', number: '42', title: '', originalText: `Ningún impuesto establecido o aumentado para sufragar la construcción de obras especiales, podrá ser aplicado interina o definitivamente a objetos distintos a los determinados en la ley de su creación, ni durará más tiempo que el que se emplee en redimir la deuda que se contraiga.`, currentText: `Ningún impuesto establecido o aumentado para sufragar la construcción de obras especiales, podrá ser aplicado interina o definitivamente a objetos distintos a los determinados en la ley de su creación, ni durará más tiempo que el que se emplee en redimir la deuda que se contraiga.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-43', lawId: 'const-mendoza', number: '43', title: '', originalText: `Los nombramientos de funcionarios y empleados que hagan los poderes públicos prescindiendo de los requisitos enumerados o exigidos por esta Constitución, son nulos, y en cualquier tiempo podrán esos empleados ser removidos de sus puestos.`, currentText: `Los nombramientos de funcionarios y empleados que hagan los poderes públicos prescindiendo de los requisitos enumerados o exigidos por esta Constitución, son nulos, y en cualquier tiempo podrán esos empleados ser removidos de sus puestos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-44', lawId: 'const-mendoza', number: '44', title: '', originalText: `En el territorio de la Provincia, es obligatorio el descanso dominical o hebdomadario, con las excepciones que la ley establezca por razones de interés público.`, currentText: `En el territorio de la Provincia, es obligatorio el descanso dominical o hebdomadario, con las excepciones que la ley establezca por razones de interés público.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-45', lawId: 'const-mendoza', number: '45', title: '', originalText: `La Legislatura dictará una ley de amparo y reglamentaria del trabajo de las mujeres y niños menores de dieciocho años, en las fábricas, talleres, casas de comercio, y demás establecimientos industriales, asegurando en general, para el obrero, las condiciones de salubridad en el trabajo y la habitación. También se dictará la reglamentación de la jornada de trabajo. Respecto de las obras o servicios públicos en establecimientos del Estado, queda fijada la jornada de ocho horas, con las excepciones que establezca la ley.`, currentText: `La Legislatura dictará una ley de amparo y reglamentaria del trabajo de las mujeres y niños menores de dieciocho años, en las fábricas, talleres, casas de comercio, y demás establecimientos industriales, asegurando en general, para el obrero, las condiciones de salubridad en el trabajo y la habitación. También se dictará la reglamentación de la jornada de trabajo. Respecto de las obras o servicios públicos en establecimientos del Estado, queda fijada la jornada de ocho horas, con las excepciones que establezca la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-46', lawId: 'const-mendoza', number: '46', title: '', originalText: `Serán demás feriados en la Provincia los determinados por ley del Congreso, o por el Poder Ejecutivo de la Nación y los que decrete el Poder Ejecutivo de aquélla. El Poder Ejecutivo y el Judicial podrán habilitar los días feriados, en caso de urgencia y por necesidades de un mejor y más rápido servicio público. El feriado judicial, será de un mes por año, en la forma que la ley establezca.`, currentText: `Serán demás feriados en la Provincia los determinados por ley del Congreso, o por el Poder Ejecutivo de la Nación y los que decrete el Poder Ejecutivo de aquélla. El Poder Ejecutivo y el Judicial podrán habilitar los días feriados, en caso de urgencia y por necesidades de un mejor y más rápido servicio público. El feriado judicial, será de un mes por año, en la forma que la ley establezca.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-47', lawId: 'const-mendoza', number: '47', title: '', originalText: `La enumeración y reconocimiento de derechos que contiene esta Constitución, no importa denegación de los demás que se derivan de la forma republicana de gobierno y de la condición natural del hombre.`, currentText: `La enumeración y reconocimiento de derechos que contiene esta Constitución, no importa denegación de los demás que se derivan de la forma republicana de gobierno y de la condición natural del hombre.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-48', lawId: 'const-mendoza', number: '48', title: '', originalText: `Toda ley, decreto, ordenanza o disposición contrarios a las prescripciones de esta Constitución o que impongan al ejercicio de las libertades y derechos reconocidos en ella, otras restricciones que las que los mismos artículos permiten, o priven a los habitantes de las garantías que aseguran, serán inconstitucionales y no podrán ser aplicados por los jueces. Las personas que sufran sus efectos, además de la acción de nulidad, tendrán derecho a reclamar las indemnizaciones por los juicios que tal violación o menoscabo les cause, contra el empleado o funcionario que los haya autorizado o ejecutado.`, currentText: `Toda ley, decreto, ordenanza o disposición contrarios a las prescripciones de esta Constitución o que impongan al ejercicio de las libertades y derechos reconocidos en ella, otras restricciones que las que los mismos artículos permiten, o priven a los habitantes de las garantías que aseguran, serán inconstitucionales y no podrán ser aplicados por los jueces. Las personas que sufran sus efectos, además de la acción de nulidad, tendrán derecho a reclamar las indemnizaciones por los juicios que tal violación o menoscabo les cause, contra el empleado o funcionario que los haya autorizado o ejecutado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-49', lawId: 'const-mendoza', number: '49', title: '', originalText: `La representación política tiene por base la población.`, currentText: `La representación política tiene por base la población.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-50', lawId: 'const-mendoza', number: '50', title: '', originalText: `El sufragio electoral es un derecho que le corresponde a todo ciudadano argentino mayor de dieciocho años y a la vez una función política que tiene el deber de desempeñar con arreglo a esta Constitución y a la ley.`, currentText: `El sufragio electoral es un derecho que le corresponde a todo ciudadano argentino mayor de dieciocho años y a la vez una función política que tiene el deber de desempeñar con arreglo a esta Constitución y a la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-51', lawId: 'const-mendoza', number: '51', title: '', originalText: `No podrá votar la tropa de línea, la Guardia Nacional movilizada, ni la policía de seguridad.`, currentText: `No podrá votar la tropa de línea, la Guardia Nacional movilizada, ni la policía de seguridad.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-52', lawId: 'const-mendoza', number: '52', title: '', originalText: `El voto será secreto y obligatorio, y el escrutinio público, en la forma que la ley determine.`, currentText: `El voto será secreto y obligatorio, y el escrutinio público, en la forma que la ley determine.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-53', lawId: 'const-mendoza', number: '53', title: '', originalText: `En ningún caso la ley electoral dejará de dar representación a la minoría.`, currentText: `En ningún caso la ley electoral dejará de dar representación a la minoría.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-54', lawId: 'const-mendoza', number: '54', title: '', originalText: `El Registro Cívico Nacional regirá para todas las elecciones de la Provincia, con arreglo a las prescripciones de esta Constitución.`, currentText: `El Registro Cívico Nacional regirá para todas las elecciones de la Provincia, con arreglo a las prescripciones de esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-55', lawId: 'const-mendoza', number: '55', title: '', originalText: `Una Junta Electoral permanente compuesta de la Suprema Corte, del presidente del Senado y del presidente de la Cámara de Diputados, o sus reemplazantes legales, tendrá a su cargo el nombramiento de los miembros de las mesas receptoras de votos, la organización y funcionamiento de los comicios y los escrutinios provisorios.`, currentText: `Una Junta Electoral permanente compuesta de la Suprema Corte, del presidente del Senado y del presidente de la Cámara de Diputados, o sus reemplazantes legales, tendrá a su cargo el nombramiento de los miembros de las mesas receptoras de votos, la organización y funcionamiento de los comicios y los escrutinios provisorios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-56', lawId: 'const-mendoza', number: '56', title: '', originalText: `La Junta Electoral permanente juzgará en primera instancia, haciendo los escrutinios provisorios, de la validez de cada comicio, otorgando a los electos, con sujeción a la ley, sus respectivos diplomas. Su decisión, con todos los antecedentes, será elevada a la Cámara o cuerpo para cuya renovación o integración se hubieren practicado las elecciones, a los efectos de los juicios definitivos que correspondan con arreglo a esta Constitución.`, currentText: `La Junta Electoral permanente juzgará en primera instancia, haciendo los escrutinios provisorios, de la validez de cada comicio, otorgando a los electos, con sujeción a la ley, sus respectivos diplomas. Su decisión, con todos los antecedentes, será elevada a la Cámara o cuerpo para cuya renovación o integración se hubieren practicado las elecciones, a los efectos de los juicios definitivos que correspondan con arreglo a esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-57', lawId: 'const-mendoza', number: '57', title: '', originalText: `Toda elección durará 8 horas por lo menos.`, currentText: `Toda elección durará 8 horas por lo menos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-58', lawId: 'const-mendoza', number: '58', title: '', originalText: `Durante las elecciones y en el radio del comicio, no habrá más autoridad policial que la de los respectivos presidentes del mismo, cuyas órdenes y resoluciones deberá cumplir la fuerza pública.`, currentText: `Durante las elecciones y en el radio del comicio, no habrá más autoridad policial que la de los respectivos presidentes del mismo, cuyas órdenes y resoluciones deberá cumplir la fuerza pública.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-59', lawId: 'const-mendoza', number: '59', title: '', originalText: `Toda falta, acto de fraude, coacción, soborno, cohecho o intimidación, ejercitados por los empleados o funcionarios públicos de cualquier categoría, como también por cualquier persona, contra los electores, antes del acto eleccionario o durante él, serán considerados como un atentado contra el derecho y la libertad electoral y penados con prisión o arresto inconmutables que fijará la ley.`, currentText: `Toda falta, acto de fraude, coacción, soborno, cohecho o intimidación, ejercitados por los empleados o funcionarios públicos de cualquier categoría, como también por cualquier persona, contra los electores, antes del acto eleccionario o durante él, serán considerados como un atentado contra el derecho y la libertad electoral y penados con prisión o arresto inconmutables que fijará la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-60', lawId: 'const-mendoza', number: '60', title: '', originalText: `La acción para acusar por faltas o delitos definidos en la ley electoral, será popular y se podrá ejercer hasta dos meses después de cometidos aquéllos. El procedimiento será sumario y el juicio deberá substanciarse y fallarse en el término de treinta días, a instancia fiscal o de cualquier ciudadano.`, currentText: `La acción para acusar por faltas o delitos definidos en la ley electoral, será popular y se podrá ejercer hasta dos meses después de cometidos aquéllos. El procedimiento será sumario y el juicio deberá substanciarse y fallarse en el término de treinta días, a instancia fiscal o de cualquier ciudadano.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-61', lawId: 'const-mendoza', number: '61', title: '', originalText: `Las elecciones se practicarán en días fijos determinados por ley, y toda convocatoria a elección ordinaria o extraordinaria se hará públicamente y por lo menos con un mes de anticipación a la fecha señalada. Exceptúanse de esta disposición las elecciones complementarias, que se harán en la forma que establezca la ley.`, currentText: `Las elecciones se practicarán en días fijos determinados por ley, y toda convocatoria a elección ordinaria o extraordinaria se hará públicamente y por lo menos con un mes de anticipación a la fecha señalada. Exceptúanse de esta disposición las elecciones complementarias, que se harán en la forma que establezca la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-62', lawId: 'const-mendoza', number: '62', title: '', originalText: `El Poder Ejecutivo sólo podrá suspender la convocatoria para elecciones, en caso de conmoción, insurrección, invasión, movilización de milicias o cualquier accidente o calamidad pública que las haga imposibles, y esto, dando cuenta a la Legislatura dentro del tercer día, para cuyo conocimiento la convocará si se hallare en receso.`, currentText: `El Poder Ejecutivo sólo podrá suspender la convocatoria para elecciones, en caso de conmoción, insurrección, invasión, movilización de milicias o cualquier accidente o calamidad pública que las haga imposibles, y esto, dando cuenta a la Legislatura dentro del tercer día, para cuyo conocimiento la convocará si se hallare en receso.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-63', lawId: 'const-mendoza', number: '63', title: '', originalText: `La ley determinará las limitaciones y prohibiciones al ejercicio del sufragio, respetando los principios fundamentales establecidos en esta Constitución.`, currentText: `La ley determinará las limitaciones y prohibiciones al ejercicio del sufragio, respetando los principios fundamentales establecidos en esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-64', lawId: 'const-mendoza', number: '64', title: '', originalText: `El Poder Legislativo de la Provincia será ejercido por dos Cámaras: una de diputados y otra de senadores, elegidos directamente por secciones electorales con arreglo a las prescripciones de esta Constitución y a la ley de elecciones.`, currentText: `El Poder Legislativo de la Provincia será ejercido por dos Cámaras: una de diputados y otra de senadores, elegidos directamente por secciones electorales con arreglo a las prescripciones de esta Constitución y a la ley de elecciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-65', lawId: 'const-mendoza', number: '65', title: '', originalText: `No pueden ser miembros de las Cámaras legislativas, los eclesiásticos regulares, los condenados por sentencia mientras dure la condena, los encausados criminalmente después de haberse dictado auto de prisión preventiva en delitos no excarcelables, y los afectados por incapacidad física o moral.`, currentText: `No pueden ser miembros de las Cámaras legislativas, los eclesiásticos regulares, los condenados por sentencia mientras dure la condena, los encausados criminalmente después de haberse dictado auto de prisión preventiva en delitos no excarcelables, y los afectados por incapacidad física o moral.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-66', lawId: 'const-mendoza', number: '66', title: '', originalText: `En ninguna de las Cámaras podrá haber más de la quinta parte de sus miembros con ciudadanía legal. En caso de resultar elegido mayor número, se determinará por sorteo los que deban ser reemplazados.`, currentText: `En ninguna de las Cámaras podrá haber más de la quinta parte de sus miembros con ciudadanía legal. En caso de resultar elegido mayor número, se determinará por sorteo los que deban ser reemplazados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-67', lawId: 'const-mendoza', number: '67', title: '', originalText: `La Cámara de Diputados se compondrá de representantes del pueblo, a base de la población de cada sección electoral en que se divida, mediante elección directa, no pudiendo exceder de cincuenta la totalidad de los diputados.`, currentText: `La Cámara de Diputados se compondrá de representantes del pueblo, a base de la población de cada sección electoral en que se divida, mediante elección directa, no pudiendo exceder de cincuenta la totalidad de los diputados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-68', lawId: 'const-mendoza', number: '68', title: '', originalText: `Ninguna sección electoral podrá elegir un número menor de 8 diputados.`, currentText: `Ninguna sección electoral podrá elegir un número menor de 8 diputados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-69', lawId: 'const-mendoza', number: '69', title: '', originalText: `La Legislatura determinará después de cada censo nacional, el número de diputados que corresponda elegir a cada seccional electoral, en proporción a su población y a fin de que en ningún caso el total de diputados exceda del número fijado en el artículo 67.`, currentText: `La Legislatura determinará después de cada censo nacional, el número de diputados que corresponda elegir a cada seccional electoral, en proporción a su población y a fin de que en ningún caso el total de diputados exceda del número fijado en el artículo 67.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-70', lawId: 'const-mendoza', number: '70', title: '', originalText: `Los diputados durarán en su representación 4 años; son reelegibles, renovándose la Cámara por mitades cada 2 años.`, currentText: `Los diputados durarán en su representación 4 años; son reelegibles, renovándose la Cámara por mitades cada 2 años.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-71', lawId: 'const-mendoza', number: '71', title: '', originalText: `En ninguna sección electoral de la Provincia podrá convocarse a elecciones de diputados integrantes por un número menor de tres diputados.`, currentText: `En ninguna sección electoral de la Provincia podrá convocarse a elecciones de diputados integrantes por un número menor de tres diputados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-72', lawId: 'const-mendoza', number: '72', title: '', originalText: `Para ser electo diputado se requiere: ciudadanía natural en ejercicio, o legal después de cinco años de obtenida; ser mayor de edad; tener dos años de residencia en la Provincia, los que no hubiesen nacido en ella.`, currentText: `Para ser electo diputado se requiere: ciudadanía natural en ejercicio, o legal después de cinco años de obtenida; ser mayor de edad; tener dos años de residencia en la Provincia, los que no hubiesen nacido en ella.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-73', lawId: 'const-mendoza', number: '73', title: '', originalText: `Es incompatible el cargo de diputado con el de funcionario o empleado público a sueldo de la Nación o de la Provincia, o de diputado o de senador de la Nación, con exepción del profesorado nacional y de las comisiones honorarias eventuales, debiendo estas últimas ser aceptadas con el consentimiento previo de la Cámara. Todo diputado que aceptase un cargo o empleo público rentado de la Nación o de la Provincia, cesará de hecho, de ser miembro de la Cámara.`, currentText: `Es incompatible el cargo de diputado con el de funcionario o empleado público a sueldo de la Nación o de la Provincia, o de diputado o de senador de la Nación, con exepción del profesorado nacional y de las comisiones honorarias eventuales, debiendo estas últimas ser aceptadas con el consentimiento previo de la Cámara. Todo diputado que aceptase un cargo o empleo público rentado de la Nación o de la Provincia, cesará de hecho, de ser miembro de la Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-74', lawId: 'const-mendoza', number: '74', title: '', originalText: `Será de competencia exclusiva de la Cámara de Diputados: 1- Ser Cámara iniciadora de las leyes de impuestos y presupuesto. 2 - Acusar ante el Senado a los funcionarios sujetos a juicio político por la Legislatura.`, currentText: `Será de competencia exclusiva de la Cámara de Diputados: 1- Ser Cámara iniciadora de las leyes de impuestos y presupuesto. 2 - Acusar ante el Senado a los funcionarios sujetos a juicio político por la Legislatura.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-75', lawId: 'const-mendoza', number: '75', title: '', originalText: `La Cámara de Senadores se compondrá de representantes del pueblo a base de la población de cada sección electoral en que se divida, mediante elección directa, no pudiendo exceder de 40 la totalidad de los senadores.`, currentText: `La Cámara de Senadores se compondrá de representantes del pueblo a base de la población de cada sección electoral en que se divida, mediante elección directa, no pudiendo exceder de 40 la totalidad de los senadores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-76', lawId: 'const-mendoza', number: '76', title: '', originalText: `Ninguna sección electoral podrá elegir un número menor de 6 senadores.`, currentText: `Ninguna sección electoral podrá elegir un número menor de 6 senadores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-77', lawId: 'const-mendoza', number: '77', title: '', originalText: `Para ser elegido senador, se requiere tener la edad de treinta años cumplidos y demás condiciones establecidas respecto a los diputados. Son también aplicables al cargo de senador, las incompatibilidades establecidas para ser diputado.`, currentText: `Para ser elegido senador, se requiere tener la edad de treinta años cumplidos y demás condiciones establecidas respecto a los diputados. Son también aplicables al cargo de senador, las incompatibilidades establecidas para ser diputado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-78', lawId: 'const-mendoza', number: '78', title: '', originalText: `Los senadores durarán 4 años en el ejercicio de sus funciones y son reelegibles. Esta Cámara se renovará por mitades cada 2 años.`, currentText: `Los senadores durarán 4 años en el ejercicio de sus funciones y son reelegibles. Esta Cámara se renovará por mitades cada 2 años.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-79', lawId: 'const-mendoza', number: '79', title: '', originalText: `En ninguna sección electoral de la Provincia podrá convocarse a elecciones de senadores integrantes por un número menor de tres senadores.`, currentText: `En ninguna sección electoral de la Provincia podrá convocarse a elecciones de senadores integrantes por un número menor de tres senadores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-80', lawId: 'const-mendoza', number: '80', title: '', originalText: `El Senado nombrará un presidente provisorio que lo presida en los casos de ausencia del vicegobernador o cuando éste ejerza las funciones de gobernador.`, currentText: `El Senado nombrará un presidente provisorio que lo presida en los casos de ausencia del vicegobernador o cuando éste ejerza las funciones de gobernador.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-81', lawId: 'const-mendoza', number: '81', title: '', originalText: `Es atribución exclusiva del Senado juzgar en juicio político a los acusados por la Cámara de Diputados.`, currentText: `Es atribución exclusiva del Senado juzgar en juicio político a los acusados por la Cámara de Diputados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-82', lawId: 'const-mendoza', number: '82', title: '', originalText: `Su fallo en dicho juicio no tendrá más efecto que destituir al acusado, pero éste quedará, no obstante, sujeto a acusación y juicio ante los tribunales ordinarios si fuere algún delito común el que motivó el juicio político.`, currentText: `Su fallo en dicho juicio no tendrá más efecto que destituir al acusado, pero éste quedará, no obstante, sujeto a acusación y juicio ante los tribunales ordinarios si fuere algún delito común el que motivó el juicio político.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-83', lawId: 'const-mendoza', number: '83', title: '', originalText: `Corresponde al Senado prestar o negar su acuerdo al Poder Ejecutivo para los nombramientos que por esta Constitución o por la ley deban hacerse con este requisito. El voto será secreto. El acuerdo se considerará prestado si el Senado no se pronuncia sobre la propuesta del Poder Ejecutivo dentro del término de treinta días a contar desde aquel en que el mensaje entró en Secretaría y estando la Cámara en funciones. En caso de ser rechazado un candidato, el Poder Ejecutivo no podrá insistir en él durante dos años, y deberá proponer el nuevo candidato dentro de los treinta días siguientes. En todos los casos, la propuesta deberá tener entrada en sesión pública y ser tratada con dos días de intervalo por lo menos.`, currentText: `Corresponde al Senado prestar o negar su acuerdo al Poder Ejecutivo para los nombramientos que por esta Constitución o por la ley deban hacerse con este requisito. El voto será secreto. El acuerdo se considerará prestado si el Senado no se pronuncia sobre la propuesta del Poder Ejecutivo dentro del término de treinta días a contar desde aquel en que el mensaje entró en Secretaría y estando la Cámara en funciones. En caso de ser rechazado un candidato, el Poder Ejecutivo no podrá insistir en él durante dos años, y deberá proponer el nuevo candidato dentro de los treinta días siguientes. En todos los casos, la propuesta deberá tener entrada en sesión pública y ser tratada con dos días de intervalo por lo menos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-84', lawId: 'const-mendoza', number: '84', title: '', originalText: `Las cámaras funcionarán en sesiones ordinarias todos los años desde el 1 de mayo al 30 de setiembre y podrán prorrogar sus sesiones por propia iniciativa hasta 30 días. En la prórroga sólo podrán ocuparse del asunto o asuntos que le hayan dado origen y de las que el Poder Ejecutivo incluyese durante ella.`, currentText: `Las cámaras funcionarán en sesiones ordinarias todos los años desde el 1 de mayo al 30 de setiembre y podrán prorrogar sus sesiones por propia iniciativa hasta 30 días. En la prórroga sólo podrán ocuparse del asunto o asuntos que le hayan dado origen y de las que el Poder Ejecutivo incluyese durante ella.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-85', lawId: 'const-mendoza', number: '85', title: '', originalText: `Abren y cierran sus sesiones ordinarias y extraordinarias, por sí mismas, reunidas en Asamblea y presididas por el presidente del Senado, debiendo dar conocimiento anticipadamente al Poder Ejecutivo. Funcionarán en la capital de la Provincia y en el recinto de la Legislatura, pero, podrán hacerlo en otro punto, por causa grave, previa resolución de ambas Cámaras.`, currentText: `Abren y cierran sus sesiones ordinarias y extraordinarias, por sí mismas, reunidas en Asamblea y presididas por el presidente del Senado, debiendo dar conocimiento anticipadamente al Poder Ejecutivo. Funcionarán en la capital de la Provincia y en el recinto de la Legislatura, pero, podrán hacerlo en otro punto, por causa grave, previa resolución de ambas Cámaras.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-86', lawId: 'const-mendoza', number: '86', title: '', originalText: `Pueden también ser convocadas extraordinariamente por el Poder Ejecutivo, como asimismo por el presidente de la Asamblea General, en virtud de petición escrita firmada por la cuarta parte de los miembros de cada Cámara, cuando un grave interés de orden o conveniencia pública lo requiera y en tales casos, se ocuparán sólo del asunto o asuntos que motiven la convocatoria.`, currentText: `Pueden también ser convocadas extraordinariamente por el Poder Ejecutivo, como asimismo por el presidente de la Asamblea General, en virtud de petición escrita firmada por la cuarta parte de los miembros de cada Cámara, cuando un grave interés de orden o conveniencia pública lo requiera y en tales casos, se ocuparán sólo del asunto o asuntos que motiven la convocatoria.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-87', lawId: 'const-mendoza', number: '87', title: '', originalText: `Cada Cámara es juez de la calidad y elección de sus miembros y de la validez de sus títulos provisorios otorgados por la Junta Electoral; pero cuando cualquiera de ellas esté en disconformidad con el fallo de la Junta, dicha resolución deberá ser considerada por la Asamblea Legislativa. La Cámara que hubiera producido la disidencia, lo comunicará inmediatamente al presidente de la Legislatura para que éste la convoque y resuelva el caso.`, currentText: `Cada Cámara es juez de la calidad y elección de sus miembros y de la validez de sus títulos provisorios otorgados por la Junta Electoral; pero cuando cualquiera de ellas esté en disconformidad con el fallo de la Junta, dicha resolución deberá ser considerada por la Asamblea Legislativa. La Cámara que hubiera producido la disidencia, lo comunicará inmediatamente al presidente de la Legislatura para que éste la convoque y resuelva el caso.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-88', lawId: 'const-mendoza', number: '88', title: '', originalText: `Ninguna Cámara podrá sesionar sin la mayoría absoluta de sus miembros, pero después de tres citaciones especiales sin poderse reunir por falta de quórum, podrá sesionar con la tercera parte de sus miembros, con excepción de los casos en que por esta Constitución se exija quórum especial. Las citaciones especiales a que se refiere este artículo se harán con un intervalo no menor de tres días y en dichas sesiones no se podrá tratar sino los asuntos a la orden del día.`, currentText: `Ninguna Cámara podrá sesionar sin la mayoría absoluta de sus miembros, pero después de tres citaciones especiales sin poderse reunir por falta de quórum, podrá sesionar con la tercera parte de sus miembros, con excepción de los casos en que por esta Constitución se exija quórum especial. Las citaciones especiales a que se refiere este artículo se harán con un intervalo no menor de tres días y en dichas sesiones no se podrá tratar sino los asuntos a la orden del día.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-89', lawId: 'const-mendoza', number: '89', title: '', originalText: `En los casos en que por renovación u otra causa no exista en ejercicio el número necesario de miembros para hacer quórum, la minoría existente bastará para juzgar de los títulos de los nuevamente electos, siempre que se halle en mayoría absoluta respecto de sí misma, pero sólo hasta poderse constituir en mayoría.`, currentText: `En los casos en que por renovación u otra causa no exista en ejercicio el número necesario de miembros para hacer quórum, la minoría existente bastará para juzgar de los títulos de los nuevamente electos, siempre que se halle en mayoría absoluta respecto de sí misma, pero sólo hasta poderse constituir en mayoría.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-90', lawId: 'const-mendoza', number: '90', title: '', originalText: `Ambas Cámaras empiezan y concluyen simultáneamente el período de sus sesiones, y ninguna de ellas podrá suspenderlas por más de tres días sin el consentimiento de la otra.`, currentText: `Ambas Cámaras empiezan y concluyen simultáneamente el período de sus sesiones, y ninguna de ellas podrá suspenderlas por más de tres días sin el consentimiento de la otra.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-91', lawId: 'const-mendoza', number: '91', title: '', originalText: `Cada Cámara hará su reglamento y podrá, con dos tercios de votos de los presentes en sesión, corregir, suspender y aún excluir de su seno a cualquiera de sus miembros, por desorden de conducta en el ejercicio de sus funciones, o por indignidad y removerlo por inhabilidad física o moral sobreviniente a su incorporación o por inasistencia notable a sus sesiones.`, currentText: `Cada Cámara hará su reglamento y podrá, con dos tercios de votos de los presentes en sesión, corregir, suspender y aún excluir de su seno a cualquiera de sus miembros, por desorden de conducta en el ejercicio de sus funciones, o por indignidad y removerlo por inhabilidad física o moral sobreviniente a su incorporación o por inasistencia notable a sus sesiones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-92', lawId: 'const-mendoza', number: '92', title: '', originalText: `Cada Cámara nombrará a sus autoridades y propondrá su respectivo presupuesto de gastos al Poder Ejecutivo para ser incluido en el proyecto general de presupuesto de la Provincia.`, currentText: `Cada Cámara nombrará a sus autoridades y propondrá su respectivo presupuesto de gastos al Poder Ejecutivo para ser incluido en el proyecto general de presupuesto de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-93', lawId: 'const-mendoza', number: '93', title: '', originalText: `Cada Cámara o sus respectivas comisiones, podrán examinar el estado del Tesoro, y para el mejor desempeño de las atribuciones que les conciernen, pedir a los jefes de repartición de la administración y por su conducto a sus subalternos, los informes que crean convenientes.`, currentText: `Cada Cámara o sus respectivas comisiones, podrán examinar el estado del Tesoro, y para el mejor desempeño de las atribuciones que les conciernen, pedir a los jefes de repartición de la administración y por su conducto a sus subalternos, los informes que crean convenientes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-94', lawId: 'const-mendoza', number: '94', title: '', originalText: `Cada Cámara podrá hacer venir a su recinto a los ministros del Poder Ejecutivo para pedirles los informes y explicaciones que estime convenientes, citándolos con un día de anticipación por lo menos, salvo los casos de urgencia y comunicándoles en la citación los puntos sobre los cuales deban informar. Esta facultad podrá ejercerla aún cuando se trate de sesiones de prórroga o extraordinarias. Podrá también, cada Cámara, pedir al Poder Ejecutivo o al Judicial, los datos e informes que crea necesarios. Cada Cámara podrá expresar su opinión por medio de resoluciones o declaraciones, sin fuerza de ley, sobre cualquier asunto que afecte a los intereses generales de la Nación o de la Provincia.`, currentText: `Cada Cámara podrá hacer venir a su recinto a los ministros del Poder Ejecutivo para pedirles los informes y explicaciones que estime convenientes, citándolos con un día de anticipación por lo menos, salvo los casos de urgencia y comunicándoles en la citación los puntos sobre los cuales deban informar. Esta facultad podrá ejercerla aún cuando se trate de sesiones de prórroga o extraordinarias. Podrá también, cada Cámara, pedir al Poder Ejecutivo o al Judicial, los datos e informes que crea necesarios. Cada Cámara podrá expresar su opinión por medio de resoluciones o declaraciones, sin fuerza de ley, sobre cualquier asunto que afecte a los intereses generales de la Nación o de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-95', lawId: 'const-mendoza', number: '95', title: '', originalText: `Las sesiones de ambas Cámaras serán públicas, a menos que un grave interés declarado por ellas mismas, exigiera lo contrario, o cuando así se determine en casos especiales en sus respectivos reglamentos.`, currentText: `Las sesiones de ambas Cámaras serán públicas, a menos que un grave interés declarado por ellas mismas, exigiera lo contrario, o cuando así se determine en casos especiales en sus respectivos reglamentos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-96', lawId: 'const-mendoza', number: '96', title: '', originalText: `Los miembros del Poder Legislativo, son inviolables por las opiniones que manifiesten y por los votos que emitan en el desempeño de su cargo. Ninguna autoridad podrá reconvenirles ni procesarles, en ningún tiempo, por tales causas. Gozarán de completa inmunidad en su persona, desde el día de su elección hasta el de su cese, y no podrán ser detenidos por ninguna autoridad, sino en caso de ser sorprendido in fraganti en la ejecución de un delito que merezca pena de prisión, en cuyo caso debe darse cuenta a la Cámara respectiva con la información sumaria del hecho, para que ésta resuelva lo que corresponda sobre la inmunidad personal.`, currentText: `Los miembros del Poder Legislativo, son inviolables por las opiniones que manifiesten y por los votos que emitan en el desempeño de su cargo. Ninguna autoridad podrá reconvenirles ni procesarles, en ningún tiempo, por tales causas. Gozarán de completa inmunidad en su persona, desde el día de su elección hasta el de su cese, y no podrán ser detenidos por ninguna autoridad, sino en caso de ser sorprendido in fraganti en la ejecución de un delito que merezca pena de prisión, en cuyo caso debe darse cuenta a la Cámara respectiva con la información sumaria del hecho, para que ésta resuelva lo que corresponda sobre la inmunidad personal.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-97', lawId: 'const-mendoza', number: '97', title: '', originalText: `Cada Cámara tendrá jurisdicción para corregir con arresto que no pase de un mes, a toda persona de fuera de su seno, que viole sus prerrogativas o privilegios, pudiendo, cuando el caso fuere grave pedir su enjuiciamiento a los tribunales ordinarios.`, currentText: `Cada Cámara tendrá jurisdicción para corregir con arresto que no pase de un mes, a toda persona de fuera de su seno, que viole sus prerrogativas o privilegios, pudiendo, cuando el caso fuere grave pedir su enjuiciamiento a los tribunales ordinarios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-98', lawId: 'const-mendoza', number: '98', title: '', originalText: `Los senadores y diputados, prestarán en el acto de su incorporación, juramento por Dios y por la Patria, o por la Patria y por su honor, de desempeñar fielmente su cargo.`, currentText: `Los senadores y diputados, prestarán en el acto de su incorporación, juramento por Dios y por la Patria, o por la Patria y por su honor, de desempeñar fielmente su cargo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-99', lawId: 'const-mendoza', number: '99', title: '', originalText: `Corresponde al Poder Legislativo: 1 - Aprobar o desechar los tratados que el Poder Ejecutivo celebrare con otras Provincias, de acuerdo con las prescripciones de la Constitución Nacional. 2 - Establecer los impuestos y contribuciones necesarios para los gastos del servicio público. 3 - Fijar anualmente el presupuesto de gastos y cálculos de recursos, no pudiendo aumentar los gastos ordinarios y sueldos proyectados por el Poder Ejecutivo. Si el Poder Ejecutivo no presentase el proyecto de presupuesto en el penúltimo mes del período ordinario de sesiones, corresponderá la iniciativa a la Legislatura, tomando por base el presupuesto vigente. Si la Legislatura no sancionare el presupuesto general de gastos hasta el 31 de diciembre, continuará el vigente en sus partidas ordinarias. 4 - Disponer el uso y enajenación de la tierra pública y demás bienes de la Provincia. 5 - Legislar sobre organización de las municipalidades y policías de acuerdo con lo establecido en esta Constitución. 6 - Determinar las divisiones territoriales para el régimen administrativo de la Provincia. 7 - Dictar leyes sobre la educación pública. 8 - Dictar una ley general de jubilaciones y pensiones civiles por servicios prestados a la Provincia, creando un fondo a base del descuento forzoso de los haberes correspondientes a los empleados que hubieren de gozar de sus beneficios. En ningún caso podrán acordarse jubilaciones por leyes especiales. 9 - Crear y suprimir empleos para la mejor administración de la Provincia, determinando sus atribuciones y responsabilidades, y dictar la ley general de sueldos. 10 - Admitir y desechar las renuncias que hicieren de sus cargos el gobernador y vicegobernador o la persona que ejerza el Poder Ejecutivo, y declarar con dos tercios de votos de los miembros que componen cada Cámara, los casos de inhabilidad física o moral de los mismos, para continuar en su desempeño, llamando al funcionario que corresponda según esta Constitución. 11 - Dictar leyes estableciendo los medios de hacer efectivas las responsabilidades civiles de los funcionarios y empleados públicos. 12 - Dictar las leyes de organización de los tribunales y de procedimientos judiciales. 13 - Reglamentar la administración del Crédito Público. 14 - Autorizar la movilización de la milicia provincial o parte de ella, en los casos a que se refiere el artículo 108 de la Constitución Nacional, y aprobar o desechar la medida cuando el Poder Ejecutivo la hubiese dictado de por sí, en el receso de las Cámaras. 15 - Conceder privilegios por un tiempo limitado, o recompensas de estímulos a los autores o inventores, perfeccionadores o primeros introductores de nuevas industrias a explotarse en la Provincia. 16 - Nombrar senadores al Congreso Nacional. 17 - Conceder indultos o amnistías por delitos políticos. 18 - Legislar sobre el registro del estado civil de las personas. 19 - Autorizar el establecimiento de bancos, dentro de las prescripciones de la Constitución Nacional. 20 - Facultar al Poder Ejecutivo para contratar empréstitos o emitir fondos públicos como lo determina esta Constitución. 21 - Dictar la ley general de elecciones. 22 - Dictar todas las leyes y reglamentos necesarios para poner en ejercicio los poderes y autoridades que establece esta Constitución, así como las conducentes al mejor desempeño de las anteriores atribuciones y para todo asunto de interés público y general de la Provincia, que por su naturaleza y objeto, no corresponda privativamente a los otros poderes provinciales o a los nacionales.`, currentText: `Corresponde al Poder Legislativo: 1 - Aprobar o desechar los tratados que el Poder Ejecutivo celebrare con otras Provincias, de acuerdo con las prescripciones de la Constitución Nacional. 2 - Establecer los impuestos y contribuciones necesarios para los gastos del servicio público. 3 - Fijar anualmente el presupuesto de gastos y cálculos de recursos, no pudiendo aumentar los gastos ordinarios y sueldos proyectados por el Poder Ejecutivo. Si el Poder Ejecutivo no presentase el proyecto de presupuesto en el penúltimo mes del período ordinario de sesiones, corresponderá la iniciativa a la Legislatura, tomando por base el presupuesto vigente. Si la Legislatura no sancionare el presupuesto general de gastos hasta el 31 de diciembre, continuará el vigente en sus partidas ordinarias. 4 - Disponer el uso y enajenación de la tierra pública y demás bienes de la Provincia. 5 - Legislar sobre organización de las municipalidades y policías de acuerdo con lo establecido en esta Constitución. 6 - Determinar las divisiones territoriales para el régimen administrativo de la Provincia. 7 - Dictar leyes sobre la educación pública. 8 - Dictar una ley general de jubilaciones y pensiones civiles por servicios prestados a la Provincia, creando un fondo a base del descuento forzoso de los haberes correspondientes a los empleados que hubieren de gozar de sus beneficios. En ningún caso podrán acordarse jubilaciones por leyes especiales. 9 - Crear y suprimir empleos para la mejor administración de la Provincia, determinando sus atribuciones y responsabilidades, y dictar la ley general de sueldos. 10 - Admitir y desechar las renuncias que hicieren de sus cargos el gobernador y vicegobernador o la persona que ejerza el Poder Ejecutivo, y declarar con dos tercios de votos de los miembros que componen cada Cámara, los casos de inhabilidad física o moral de los mismos, para continuar en su desempeño, llamando al funcionario que corresponda según esta Constitución. 11 - Dictar leyes estableciendo los medios de hacer efectivas las responsabilidades civiles de los funcionarios y empleados públicos. 12 - Dictar las leyes de organización de los tribunales y de procedimientos judiciales. 13 - Reglamentar la administración del Crédito Público. 14 - Autorizar la movilización de la milicia provincial o parte de ella, en los casos a que se refiere el artículo 108 de la Constitución Nacional, y aprobar o desechar la medida cuando el Poder Ejecutivo la hubiese dictado de por sí, en el receso de las Cámaras. 15 - Conceder privilegios por un tiempo limitado, o recompensas de estímulos a los autores o inventores, perfeccionadores o primeros introductores de nuevas industrias a explotarse en la Provincia. 16 - Nombrar senadores al Congreso Nacional. 17 - Conceder indultos o amnistías por delitos políticos. 18 - Legislar sobre el registro del estado civil de las personas. 19 - Autorizar el establecimiento de bancos, dentro de las prescripciones de la Constitución Nacional. 20 - Facultar al Poder Ejecutivo para contratar empréstitos o emitir fondos públicos como lo determina esta Constitución. 21 - Dictar la ley general de elecciones. 22 - Dictar todas las leyes y reglamentos necesarios para poner en ejercicio los poderes y autoridades que establece esta Constitución, así como las conducentes al mejor desempeño de las anteriores atribuciones y para todo asunto de interés público y general de la Provincia, que por su naturaleza y objeto, no corresponda privativamente a los otros poderes provinciales o a los nacionales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-100', lawId: 'const-mendoza', number: '100', title: '', originalText: `Las leyes pueden tener principio, salvo los casos que esta Constitución exceptúa, en cualquiera de las dos Cámaras, por proyecto presentado por alguno o algunos de sus miembros, o por el Poder Ejecutivo.`, currentText: `Las leyes pueden tener principio, salvo los casos que esta Constitución exceptúa, en cualquiera de las dos Cámaras, por proyecto presentado por alguno o algunos de sus miembros, o por el Poder Ejecutivo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-101', lawId: 'const-mendoza', number: '101', title: '', originalText: `Aprobado un proyecto por la Cámara de su origen, pasará en revisión a la otra, y si ésta también lo aprobase, se comunicará al Poder Ejecutivo para su promulgación. Se reputa promulgado por el Poder Ejecutivo, todo proyecto no devuelto en el término de 10 días.`, currentText: `Aprobado un proyecto por la Cámara de su origen, pasará en revisión a la otra, y si ésta también lo aprobase, se comunicará al Poder Ejecutivo para su promulgación. Se reputa promulgado por el Poder Ejecutivo, todo proyecto no devuelto en el término de 10 días.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-102', lawId: 'const-mendoza', number: '102', title: '', originalText: `Desechado en todo o en parte el proyecto por el Poder Ejecutivo, lo devolverá con sus observaciones y será reconsiderado, primero en la Cámara de su origen y después en la revisora; y si ambas insistiesen en su sanción por dos tercios de los miembros presentes, el proyecto será ley y pasará al Poder Ejecutivo para su inmediata promulgación. No insistiendo la Legislatura en su sanción, el proyecto no podrá repetirse en las sesiones del año. En cuanto a la ley de presupuesto y a las leyes de impuestos que fuesen observadas por el Poder Ejecutivo, sólo serán reconsideradas en la parte objetada, quedando en vigencia lo demás de ellas. De hecho se considerarán prorrogadas las sesiones hasta terminar la sanción de las mismas.`, currentText: `Desechado en todo o en parte el proyecto por el Poder Ejecutivo, lo devolverá con sus observaciones y será reconsiderado, primero en la Cámara de su origen y después en la revisora; y si ambas insistiesen en su sanción por dos tercios de los miembros presentes, el proyecto será ley y pasará al Poder Ejecutivo para su inmediata promulgación. No insistiendo la Legislatura en su sanción, el proyecto no podrá repetirse en las sesiones del año. En cuanto a la ley de presupuesto y a las leyes de impuestos que fuesen observadas por el Poder Ejecutivo, sólo serán reconsideradas en la parte objetada, quedando en vigencia lo demás de ellas. De hecho se considerarán prorrogadas las sesiones hasta terminar la sanción de las mismas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-103', lawId: 'const-mendoza', number: '103', title: '', originalText: `Ningún proyecto de ley, rechazado totalmente por una de las Cámaras, podrá repetirse en las sesiones del año. Pero, si sólo fuese adicional lo corregido por la Cámara revisora, volverá a la de su origen, y si en ésta se aprobasen las adiciones o correcciones por mayoría absoluta, pasará al Poder Ejecutivo. Si las adiciones o correcciones fuesen desechadas, volverá por segunda vez el proyecto a la Cámara revisora, y si ella no tuviese dos tercios de votos para insistir, prevalecerá la sanción de la iniciadora; pero si concurriesen dos tercios de votos para sostener las modificaciones, el proyectos pasará de nuevo a la Cámara de su origen y no se entenderá que ésta reprueba las correcciones o adiciones, si no concurre para ello, el voto de las dos terceras partes de sus miembros presentes.`, currentText: `Ningún proyecto de ley, rechazado totalmente por una de las Cámaras, podrá repetirse en las sesiones del año. Pero, si sólo fuese adicional lo corregido por la Cámara revisora, volverá a la de su origen, y si en ésta se aprobasen las adiciones o correcciones por mayoría absoluta, pasará al Poder Ejecutivo. Si las adiciones o correcciones fuesen desechadas, volverá por segunda vez el proyecto a la Cámara revisora, y si ella no tuviese dos tercios de votos para insistir, prevalecerá la sanción de la iniciadora; pero si concurriesen dos tercios de votos para sostener las modificaciones, el proyectos pasará de nuevo a la Cámara de su origen y no se entenderá que ésta reprueba las correcciones o adiciones, si no concurre para ello, el voto de las dos terceras partes de sus miembros presentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-104', lawId: 'const-mendoza', number: '104', title: '', originalText: `En la sanción de las leyes se usará la siguiente fórmula: El Senado y Cámara de Diputados de la Provincia de Mendoza, sancionan con fuerza de ley, etcétera.`, currentText: `En la sanción de las leyes se usará la siguiente fórmula: El Senado y Cámara de Diputados de la Provincia de Mendoza, sancionan con fuerza de ley, etcétera.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-105', lawId: 'const-mendoza', number: '105', title: '', originalText: `Ambas Cámaras sólo se reunirán en Asamblea para el desempeño de las funciones siguientes: 1 - Apertura de las sesiones. 2 - Para recibir el juramento de ley al gobernador y vicegobernador de la Provincia. 3 - Para tomar en consideración la renuncia de los mismos funcionarios. 4 - Para verificar la elección de senadores al Congreso Nacional. 5 - Para considerar en última instancia las elecciones de diputados y senadores en el caso previsto en el artículo 87 de esta Constitución. 6 - Para los demás actos determinados en esta Constitución y en las leyes que dicte la Legislatura.`, currentText: `Ambas Cámaras sólo se reunirán en Asamblea para el desempeño de las funciones siguientes: 1 - Apertura de las sesiones. 2 - Para recibir el juramento de ley al gobernador y vicegobernador de la Provincia. 3 - Para tomar en consideración la renuncia de los mismos funcionarios. 4 - Para verificar la elección de senadores al Congreso Nacional. 5 - Para considerar en última instancia las elecciones de diputados y senadores en el caso previsto en el artículo 87 de esta Constitución. 6 - Para los demás actos determinados en esta Constitución y en las leyes que dicte la Legislatura.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-106', lawId: 'const-mendoza', number: '106', title: '', originalText: `De las excusaciones que se presenten de nombramientos hechos por la Asamblea, conocerá ella misma, procediendo a un nuevo nombramiento en caso de aceptación de aquéllas.`, currentText: `De las excusaciones que se presenten de nombramientos hechos por la Asamblea, conocerá ella misma, procediendo a un nuevo nombramiento en caso de aceptación de aquéllas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-107', lawId: 'const-mendoza', number: '107', title: '', originalText: `Las reuniones de la Asamblea General serán presididas por el presidente del Senado o en su defecto por el presidente provisorio del mismo, o por el presidente de la Cámara de Diputados, o por los vices de cada Cámara en su orden. En el caso de no concurrir a la Asamblea ninguno de los presidentes determinados en este artículo, la Asamblea designará uno, ad hoc, por mayoría de votos.`, currentText: `Las reuniones de la Asamblea General serán presididas por el presidente del Senado o en su defecto por el presidente provisorio del mismo, o por el presidente de la Cámara de Diputados, o por los vices de cada Cámara en su orden. En el caso de no concurrir a la Asamblea ninguno de los presidentes determinados en este artículo, la Asamblea designará uno, ad hoc, por mayoría de votos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-108', lawId: 'const-mendoza', number: '108', title: '', originalText: `No podrá funcionar la Asamblea sin la mayoría absoluta de los miembros de cada Cámara.`, currentText: `No podrá funcionar la Asamblea sin la mayoría absoluta de los miembros de cada Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-109', lawId: 'const-mendoza', number: '109', title: '', originalText: `El gobernador de la Provincia y sus ministros, el vicegobernador, los miembros de la Suprema Corte y el procurador de ésta, son acusables en juicio político ante la Legislatura por mal desempeño, desorden de conducta, faltas o delitos en el ejercicio de sus funciones o por crímenes comunes. Cualquier habitante de la Provincia, en pleno goce de su capacidad civil, puede presentar su acusación a los efectos de provocar el enjuiciamiento. Toda acusación contra un funcionario sujeto a juicio político por la Legislatura, deberá presentarse a la Cámara de Diputados, donde se observarán los trámites y formalidades siguientes. 1 - La acusación se hará por escrito, determinando con toda precisión los hechos que le sirvan de fundamento. 2 - Una vez presentada, la Cámara decidirá por votación nominal y a simple mayoría de votos, si los cargos que aquella contiene importan falta o delito que dé lugar a juicio político. Si la decisión es en sentido negativo, la acusación quedará de hecho desestimada. Si fuere en sentido afirmativo, pasará a la comisión a que se refiere el inciso siguiente. 3 - En una de sus primeras sesiones ordinarias la Cámara de Diputados nombrará anualmente, por votación directa, una comisión encargada de investigar la verdad de los hechos en que se funden las acusaciones que se promuevan, quedando a este fin revestida de amplias facultades. 4 - El acusado tendrá derecho de ser oído por la Comisión de Investigación, de interrogar por su intermedio a los testigos y de presentar los documentos de descargo que tuviere y hacer uso de todos los medios de prueba admitidos por la ley. 5 - La Comisión de Investigación consignará por escrito todas las declaraciones y demás pruebas relativas al proceso, el que elevará a la Cámara con un informe escrito, en que expresará su dictamen fundado, en favor o en contra de la acusación. La comisión deberá terminar su cometido en el perentorio término de 30 días hábiles. 6 - La Cámara decidirá si se acepta o no el dictamen de la Comisión de Investigación, necesitando para aceptarlo, cuando el dictamen fuese favorable a la acusación, el voto de dos tercios de los miembros que la componen. Para aceptar el dictamen favorable al acusado, bastará la mayoría de los miembros presentes en sesión. 7 - Desde el momento en que la Cámara haya aceptado la acusación contra un funcionario público, éste quedará suspendido en sus funciones. 8 - En la misma sesión en que se admite la acusación, la Cámara nombrará de su seno, una comisión de tres miembros para que la sostenga ante el Senado, al cual será comunicado inmediatamente dicho nombramiento y la acusación formulada. 9 - El Senado se constituirá en Cámara de Justicia y en seguida señalará el término dentro del cual deba el acusado contestar la acusación, citándosele al efecto y entregándosele en el acto de la citación copia de la acusación y de los documentos con que haya sido instruida. El acusado podrá comparecer por sí o por apoderado y si no compareciese será juzgado en rebeldía. El término para responder a la acusación no será menor de 9 días ni mayor de 20. 10 - Se leerán en sesión pública tanto la acusación como la defensa. Luego se recibirá la causa a prueba, fijando previamente el Senado, los hechos a que debe concretarse y señalando también un término suficiente para producirla. 11-Vencido el término de prueba, el Senado designará un día para oír en sesión pública a la comisión acusadora y al acusado, sobre el mérito de la información producida. Se garantiza en este juicio la libre defensa y la libre representación. 12 - Concluida la causa, los senadores discutirán en sesión secreta, el mérito de la acusación y la defensa, como asimismo de las pruebas producidas en relación a sus fundamentos. Terminada esta discusión, se designará un día para pronunciar en sesión pública el veredicto definitivo, lo que se efectuará por votación nominal sobre cada cargo, por sí o por no. 13- Ningún acusado podría ser declarado culpable sin una mayoría de dos tercios de votos de los miembros del Senado presentes en sesión. Si de la votación resultase que no hay números suficientes para condenar al acusado, se le declarará absuelto. En caso contrario, el Senado procederá a redactar la sentencia, que no podrá tener más efectos que los determinados en el artículo 165, inciso 10 de esta Constitución. 14 - Declarado absuelto el acusado, quedará ipso facto restablecido en la posesión del empleo y reintegrado en todos sus derechos con efecto al día de la suspensión. 15 - La duración del trámite en cada Cámara no excederá de 60 días hábiles, so pena de quedar sin efecto el juicio.`, currentText: `El gobernador de la Provincia y sus ministros, el vicegobernador, los miembros de la Suprema Corte y el procurador de ésta, son acusables en juicio político ante la Legislatura por mal desempeño, desorden de conducta, faltas o delitos en el ejercicio de sus funciones o por crímenes comunes. Cualquier habitante de la Provincia, en pleno goce de su capacidad civil, puede presentar su acusación a los efectos de provocar el enjuiciamiento. Toda acusación contra un funcionario sujeto a juicio político por la Legislatura, deberá presentarse a la Cámara de Diputados, donde se observarán los trámites y formalidades siguientes. 1 - La acusación se hará por escrito, determinando con toda precisión los hechos que le sirvan de fundamento. 2 - Una vez presentada, la Cámara decidirá por votación nominal y a simple mayoría de votos, si los cargos que aquella contiene importan falta o delito que dé lugar a juicio político. Si la decisión es en sentido negativo, la acusación quedará de hecho desestimada. Si fuere en sentido afirmativo, pasará a la comisión a que se refiere el inciso siguiente. 3 - En una de sus primeras sesiones ordinarias la Cámara de Diputados nombrará anualmente, por votación directa, una comisión encargada de investigar la verdad de los hechos en que se funden las acusaciones que se promuevan, quedando a este fin revestida de amplias facultades. 4 - El acusado tendrá derecho de ser oído por la Comisión de Investigación, de interrogar por su intermedio a los testigos y de presentar los documentos de descargo que tuviere y hacer uso de todos los medios de prueba admitidos por la ley. 5 - La Comisión de Investigación consignará por escrito todas las declaraciones y demás pruebas relativas al proceso, el que elevará a la Cámara con un informe escrito, en que expresará su dictamen fundado, en favor o en contra de la acusación. La comisión deberá terminar su cometido en el perentorio término de 30 días hábiles. 6 - La Cámara decidirá si se acepta o no el dictamen de la Comisión de Investigación, necesitando para aceptarlo, cuando el dictamen fuese favorable a la acusación, el voto de dos tercios de los miembros que la componen. Para aceptar el dictamen favorable al acusado, bastará la mayoría de los miembros presentes en sesión. 7 - Desde el momento en que la Cámara haya aceptado la acusación contra un funcionario público, éste quedará suspendido en sus funciones. 8 - En la misma sesión en que se admite la acusación, la Cámara nombrará de su seno, una comisión de tres miembros para que la sostenga ante el Senado, al cual será comunicado inmediatamente dicho nombramiento y la acusación formulada. 9 - El Senado se constituirá en Cámara de Justicia y en seguida señalará el término dentro del cual deba el acusado contestar la acusación, citándosele al efecto y entregándosele en el acto de la citación copia de la acusación y de los documentos con que haya sido instruida. El acusado podrá comparecer por sí o por apoderado y si no compareciese será juzgado en rebeldía. El término para responder a la acusación no será menor de 9 días ni mayor de 20. 10 - Se leerán en sesión pública tanto la acusación como la defensa. Luego se recibirá la causa a prueba, fijando previamente el Senado, los hechos a que debe concretarse y señalando también un término suficiente para producirla. 11-Vencido el término de prueba, el Senado designará un día para oír en sesión pública a la comisión acusadora y al acusado, sobre el mérito de la información producida. Se garantiza en este juicio la libre defensa y la libre representación. 12 - Concluida la causa, los senadores discutirán en sesión secreta, el mérito de la acusación y la defensa, como asimismo de las pruebas producidas en relación a sus fundamentos. Terminada esta discusión, se designará un día para pronunciar en sesión pública el veredicto definitivo, lo que se efectuará por votación nominal sobre cada cargo, por sí o por no. 13- Ningún acusado podría ser declarado culpable sin una mayoría de dos tercios de votos de los miembros del Senado presentes en sesión. Si de la votación resultase que no hay números suficientes para condenar al acusado, se le declarará absuelto. En caso contrario, el Senado procederá a redactar la sentencia, que no podrá tener más efectos que los determinados en el artículo 165, inciso 10 de esta Constitución. 14 - Declarado absuelto el acusado, quedará ipso facto restablecido en la posesión del empleo y reintegrado en todos sus derechos con efecto al día de la suspensión. 15 - La duración del trámite en cada Cámara no excederá de 60 días hábiles, so pena de quedar sin efecto el juicio.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-110', lawId: 'const-mendoza', number: '110', title: '', originalText: `La ley reglamentará el trámite de este juicio de modo que se ajuste a los términos y bases precedentes.`, currentText: `La ley reglamentará el trámite de este juicio de modo que se ajuste a los términos y bases precedentes.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-111', lawId: 'const-mendoza', number: '111', title: '', originalText: `El Poder Ejecutivo será desempeñado por un ciudadano con el título de gobernador de la Provincia.`, currentText: `El Poder Ejecutivo será desempeñado por un ciudadano con el título de gobernador de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-112', lawId: 'const-mendoza', number: '112', title: '', originalText: `Al mismo tiempo y por el mismo período que se elija gobernador, será elegido un vicegobernador.`, currentText: `Al mismo tiempo y por el mismo período que se elija gobernador, será elegido un vicegobernador.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-113', lawId: 'const-mendoza', number: '113', title: '', originalText: `Para ser elegido gobernador o vicegobernador se requiere: 1 - Haber nacido en territorio argentino o ser hijos de padres nativos, habiendo optado por la ciudadanía de sus padres si hubiera nacido en territorio extranjero. 2 - Haber cumplido 30 años de edad. 3 - Haber residido en la Provincia durante 5 años con ejercicio de ciudadanía no interrumpida, si no hubiese nacido en ella.`, currentText: `Para ser elegido gobernador o vicegobernador se requiere: 1 - Haber nacido en territorio argentino o ser hijos de padres nativos, habiendo optado por la ciudadanía de sus padres si hubiera nacido en territorio extranjero. 2 - Haber cumplido 30 años de edad. 3 - Haber residido en la Provincia durante 5 años con ejercicio de ciudadanía no interrumpida, si no hubiese nacido en ella.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-114', lawId: 'const-mendoza', number: '114', title: '', originalText: `El gobernador y el vicegobernador durarán 4 años en el ejercicio de sus funciones y cesarán en ellas el mismo día en que expire el período legal, sin que evento alguno determine su prorrogación por un día más, ni tampoco se lo complete más tarde. El gobernador y el vicegobernador gozarán del sueldo que la ley determine, el cual podrá ser aumentado, durante el período de su nombramiento, con el voto de los dos tercios de los miembros de cada Cámara. No podrán ejercer otro empleo ni recibir otro emolumento de la Nación o de la Provincia.`, currentText: `El gobernador y el vicegobernador durarán 4 años en el ejercicio de sus funciones y cesarán en ellas el mismo día en que expire el período legal, sin que evento alguno determine su prorrogación por un día más, ni tampoco se lo complete más tarde. El gobernador y el vicegobernador gozarán del sueldo que la ley determine, el cual podrá ser aumentado, durante el período de su nombramiento, con el voto de los dos tercios de los miembros de cada Cámara. No podrán ejercer otro empleo ni recibir otro emolumento de la Nación o de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-115', lawId: 'const-mendoza', number: '115', title: '', originalText: `El gobernador y el vicegobernador no podrán ser reelegidos para el período siguiente al de su ejercicio. Tampoco podrá el gobernador ser nombrado vicegobernador, ni el vicegobernador podrá ser nombrado gobernador. No podrán ser electos para ninguno de estos cargos, los parientes de los funcionarios salientes, dentro del segundo grado de consanguinidad o afinidad. El gobernador tampoco podrá ser electo senador nacional hasta un año después de haber terminado su mandato.`, currentText: `El gobernador y el vicegobernador no podrán ser reelegidos para el período siguiente al de su ejercicio. Tampoco podrá el gobernador ser nombrado vicegobernador, ni el vicegobernador podrá ser nombrado gobernador. No podrán ser electos para ninguno de estos cargos, los parientes de los funcionarios salientes, dentro del segundo grado de consanguinidad o afinidad. El gobernador tampoco podrá ser electo senador nacional hasta un año después de haber terminado su mandato.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-116', lawId: 'const-mendoza', number: '116', title: '', originalText: `En caso de muerte, destitución, renuncia, enfermedad, suspensión o ausencia, las funciones del gobernador serán desempeñadas por el vicegobernador, por todo el resto del período legal, en los tres primeros casos, o hasta que haya cesado la inhabilidad accidental, en los tres últimos.`, currentText: `En caso de muerte, destitución, renuncia, enfermedad, suspensión o ausencia, las funciones del gobernador serán desempeñadas por el vicegobernador, por todo el resto del período legal, en los tres primeros casos, o hasta que haya cesado la inhabilidad accidental, en los tres últimos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-117', lawId: 'const-mendoza', number: '117', title: '', originalText: `En caso de separación u otro impedimento simultáneo de los que determina el artículo anterior, del gobernador y vicegobernador, las funciones del Poder Ejecutivo serán desempeñadas por el presidente provisorio del Senado y en defecto de éste, por el presidente de la Cámara de Diputados, cada uno de los que, en su caso, convocará dentro de 3 días a la Provincia a una nueva elección para llenar el período de que se trate, siempre que de éste falte cuando menos un año y que la separación o impedimento del gobernador y vicegobernador sean absolutos. En caso de ausencia de los funcionarios determinados en este artículo, ejercerá provisoriamente las funciones de gobernador, el presidente de la Suprema Corte de Justicia.`, currentText: `En caso de separación u otro impedimento simultáneo de los que determina el artículo anterior, del gobernador y vicegobernador, las funciones del Poder Ejecutivo serán desempeñadas por el presidente provisorio del Senado y en defecto de éste, por el presidente de la Cámara de Diputados, cada uno de los que, en su caso, convocará dentro de 3 días a la Provincia a una nueva elección para llenar el período de que se trate, siempre que de éste falte cuando menos un año y que la separación o impedimento del gobernador y vicegobernador sean absolutos. En caso de ausencia de los funcionarios determinados en este artículo, ejercerá provisoriamente las funciones de gobernador, el presidente de la Suprema Corte de Justicia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-118', lawId: 'const-mendoza', number: '118', title: '', originalText: `El gobernador y vicegobernador en ejercicio de sus funciones, residirán en la capital de la Provincia, y no podrán ausentarse de ella por más de 30 días sin permiso de las Cámaras y por más de 10 días del territorrio de la Provincia, sin el mismo requisito.`, currentText: `El gobernador y vicegobernador en ejercicio de sus funciones, residirán en la capital de la Provincia, y no podrán ausentarse de ella por más de 30 días sin permiso de las Cámaras y por más de 10 días del territorrio de la Provincia, sin el mismo requisito.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-119', lawId: 'const-mendoza', number: '119', title: '', originalText: `El gobernador y vicegobernador prestarán ante la Asamblea Legislativa en el acto de tomar posesión de sus cargos, juramento por Dios y por la Patria o por la Patria y por su honor, de desempeñarlos fielmente. En caso de que la Asamblea no consiguiera quórum, el juramento será presentado ante la Suprema Corte de Justicia.`, currentText: `El gobernador y vicegobernador prestarán ante la Asamblea Legislativa en el acto de tomar posesión de sus cargos, juramento por Dios y por la Patria o por la Patria y por su honor, de desempeñarlos fielmente. En caso de que la Asamblea no consiguiera quórum, el juramento será presentado ante la Suprema Corte de Justicia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-120', lawId: 'const-mendoza', number: '120', title: '', originalText: `El gobernador y vicegobernador serán elegidos simultáneamente y directamente por el pueblo de la Provincia, cuyo territorio a ese efecto formará un distrito único, mediante una fórmula que presentarán los partidos políticos habilitados, de acuerdo con las disposiciones de la Ley Electoral Provincial. Se proclamará electa la fórmula de candidatos que obtuviere simple mayoría de los votos emitidos. El presente artículo no será aplicado para la elección de intendente la que se regirá por las normas del art. 198 y concordantes de esta Constitución.`, currentText: `El gobernador y vicegobernador serán elegidos simultáneamente y directamente por el pueblo de la Provincia, cuyo territorio a ese efecto formará un distrito único, mediante una fórmula que presentarán los partidos políticos habilitados, de acuerdo con las disposiciones de la Ley Electoral Provincial. Se proclamará electa la fórmula de candidatos que obtuviere simple mayoría de los votos emitidos. El presente artículo no será aplicado para la elección de intendente la que se regirá por las normas del art. 198 y concordantes de esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-121', lawId: 'const-mendoza', number: '121', title: '', originalText: `La elección de electores se efectuará en la fecha y forma que determine la ley electoral, y deberá serlo entre los 180 y los 60 días anteriores a la renovación gubernativa. La convocatoria se hará por el Poder Ejecutivo, con 60 días, al menos, de anticipación.`, currentText: `La elección de electores se efectuará en la fecha y forma que determine la ley electoral, y deberá serlo entre los 180 y los 60 días anteriores a la renovación gubernativa. La convocatoria se hará por el Poder Ejecutivo, con 60 días, al menos, de anticipación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-122', lawId: 'const-mendoza', number: '122', title: '', originalText: `Dentro de los 15 y 30 días posteriores a su proclamación, se reunirán los electores en la sede de la Honorable Legislatura y procederán a designar de entre sus miembros un presidente, un vicepresidente y un secretario. Inmediatamente después elegirán gobernador y vicegobernador por cédulas firmadas, expresando en una la persona por quien votan para gobernador y en otra distinta la persona que eligen para vicegobernador. Los que reúnan, en ambos casos, la mayoría absoluta de todos los votos, serán proclamados de inmediato gobernador y vicegobernador por el presidente de la Junta de Electores.`, currentText: `Dentro de los 15 y 30 días posteriores a su proclamación, se reunirán los electores en la sede de la Honorable Legislatura y procederán a designar de entre sus miembros un presidente, un vicepresidente y un secretario. Inmediatamente después elegirán gobernador y vicegobernador por cédulas firmadas, expresando en una la persona por quien votan para gobernador y en otra distinta la persona que eligen para vicegobernador. Los que reúnan, en ambos casos, la mayoría absoluta de todos los votos, serán proclamados de inmediato gobernador y vicegobernador por el presidente de la Junta de Electores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-123', lawId: 'const-mendoza', number: '123', title: '', originalText: `En caso de que por dividirse la votación no hubiese mayoría absoluta, se reunirá la Asamblea Legislativa en un plazo máximo de 15 días y elegirá entre las dos personas que hubiesen obtenido mayor número de sufragios. Si la primera mayoría que resultare, hubiese cabido a más de dos personas, elegirá la Asamblea entre todas éstas. Si la primera mayoría hubiese cabido a una sola persona, y la segunda a dos o más, elegirá la Asamblea entre todas las personas que hayan obtenido la primera y la segunda mayoría. Esta elección se hará a pluralidad absoluta de sufragios y por votación nominal. La Asamblea Legislativa será convocada por su presidente ante la comunicación de la Junta de Electores, quien la formulará dentro de las 48 horas. En caso de que ésta no los hiciese, o no se hubiese pronunciado, la convocatoria se hará a pedido de cualquier elector. Tanto en la Junta de Electores como en la Asamblea Legislativa no se podrán computar votos a favor de ningún candidato que no hubiere sido proclamado antes del comicio por alguno de los partidos políticos representados en la Junta de Electores. No regirá esta limitación para la Junta de Electores o la Asamblea, en su caso, si se produjese el fallecimiento o renuncia de cualquier candidato a gobernador o vicegobernador de los partidos representados en la Junta de Electores.`, currentText: `En caso de que por dividirse la votación no hubiese mayoría absoluta, se reunirá la Asamblea Legislativa en un plazo máximo de 15 días y elegirá entre las dos personas que hubiesen obtenido mayor número de sufragios. Si la primera mayoría que resultare, hubiese cabido a más de dos personas, elegirá la Asamblea entre todas éstas. Si la primera mayoría hubiese cabido a una sola persona, y la segunda a dos o más, elegirá la Asamblea entre todas las personas que hayan obtenido la primera y la segunda mayoría. Esta elección se hará a pluralidad absoluta de sufragios y por votación nominal. La Asamblea Legislativa será convocada por su presidente ante la comunicación de la Junta de Electores, quien la formulará dentro de las 48 horas. En caso de que ésta no los hiciese, o no se hubiese pronunciado, la convocatoria se hará a pedido de cualquier elector. Tanto en la Junta de Electores como en la Asamblea Legislativa no se podrán computar votos a favor de ningún candidato que no hubiere sido proclamado antes del comicio por alguno de los partidos políticos representados en la Junta de Electores. No regirá esta limitación para la Junta de Electores o la Asamblea, en su caso, si se produjese el fallecimiento o renuncia de cualquier candidato a gobernador o vicegobernador de los partidos representados en la Junta de Electores.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-124', lawId: 'const-mendoza', number: '124', title: '', originalText: `Si verificada la primera votación no resultare mayoría absoluta, se hará por segunda vez, contrayéndose la votación a las dos personas que en la primera hubiesen obtenido mayor número de sufragios. En caso de empate, se repetirá la votación y si resultare nuevo empate, decidirá con su voto el presidente de la Asamblea Legislativa, la que no podrá funcionar sin el quórum previsto por el art. 108 de esta Constitución.`, currentText: `Si verificada la primera votación no resultare mayoría absoluta, se hará por segunda vez, contrayéndose la votación a las dos personas que en la primera hubiesen obtenido mayor número de sufragios. En caso de empate, se repetirá la votación y si resultare nuevo empate, decidirá con su voto el presidente de la Asamblea Legislativa, la que no podrá funcionar sin el quórum previsto por el art. 108 de esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-125', lawId: 'const-mendoza', number: '125', title: '', originalText: `En el supuesto de que la Junta de Electores no se reuniese en el plazo previsto en el art. 122, la Asamblea Legislativa, elegirá gobernador y vicegobernador por mayoría absoluta de todos los votos. Si no obtuviese esa mayoría en la primera votación, se aplicará el procedimiento establecido en los artículos precedentes, para el caso de dividirse la votación en la Junta de Electores. El resultado de la elección practicada por la Junta de Electores o por la Asamblea Legislativa, en su caso, deberá publicarse de inmediato y comunicarse al Poder Ejecutivo.`, currentText: `En el supuesto de que la Junta de Electores no se reuniese en el plazo previsto en el art. 122, la Asamblea Legislativa, elegirá gobernador y vicegobernador por mayoría absoluta de todos los votos. Si no obtuviese esa mayoría en la primera votación, se aplicará el procedimiento establecido en los artículos precedentes, para el caso de dividirse la votación en la Junta de Electores. El resultado de la elección practicada por la Junta de Electores o por la Asamblea Legislativa, en su caso, deberá publicarse de inmediato y comunicarse al Poder Ejecutivo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-126', lawId: 'const-mendoza', number: '126', title: '', originalText: `Si antes de recibirse el ciudadano nombrado gobernador muriese, renunciase o por cualquier otro impedimento no pudiese ocupar ese cargo, se procederá a nueva elección, a cuyo efecto la Junta Electoral de la Provincia lo comunicará inmediatamente al Poder Ejecutivo, para que haga la convocatoria en los plazos que determina el art. 121 de esta Constitución. Si en ese caso llegase el día en que debe cesar el gobernador saliente sin que se haya hecho la elección y proclamación del nuevo gobernador, el vicegobernador electo ocupará el cargo hasta que el gobernador sea elegido y proclamado.`, currentText: `Si antes de recibirse el ciudadano nombrado gobernador muriese, renunciase o por cualquier otro impedimento no pudiese ocupar ese cargo, se procederá a nueva elección, a cuyo efecto la Junta Electoral de la Provincia lo comunicará inmediatamente al Poder Ejecutivo, para que haga la convocatoria en los plazos que determina el art. 121 de esta Constitución. Si en ese caso llegase el día en que debe cesar el gobernador saliente sin que se haya hecho la elección y proclamación del nuevo gobernador, el vicegobernador electo ocupará el cargo hasta que el gobernador sea elegido y proclamado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-127', lawId: 'const-mendoza', number: '127', title: '', originalText: `Si antes o después de recibirse ocurriese respecto del vicegobernador alguno de los casos designados en el artículo anterior, se procederá a elegirlo nuevamente para completar período, en la siguiente elección de renovación legislativa, haciéndose la convocatoria en los plazos que determina el art. 121 de esta Constitución, salvo lo dispuesto en el art. 117.`, currentText: `Si antes o después de recibirse ocurriese respecto del vicegobernador alguno de los casos designados en el artículo anterior, se procederá a elegirlo nuevamente para completar período, en la siguiente elección de renovación legislativa, haciéndose la convocatoria en los plazos que determina el art. 121 de esta Constitución, salvo lo dispuesto en el art. 117.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-128', lawId: 'const-mendoza', number: '128', title: '', originalText: `El gobernador es el jefe del Poder Ejecutivo y tiene las siguientes atribuciones y deberes: 1 - Tiene a su cargo la administración general de la Provincia. 2 - Participa en la formación de las leyes con arreglo a esta Constitución, las promulga y expide decretos, instrumentos o reglamentos para su ejecución, sin alterar su espíritu. 3 - Inicia leyes o propone la modificación o derogación de las existentes, por proyectos presentados a las Cámaras. 4 - Hace la convocatoria para las elecciones populares conforme a esta Constitución. 5 - Podrá indultar o conmutar las penas impuestas por delitos sujetos a la jurisdicción provincial, previo informe motivado de la Suprema Corte sobre la oportunidad y conveniencia del indulto o conmutación y con arreglo a la ley reglamentaria que determinará los casos y la forma en que pueda solicitarse. El gobernador no podrá ejercer esta atribución cuando se trate de delitos cometidos por funcionarios públicos en el ejercicio de sus funciones. 6 - Celebra y firma tratados parciales con las demás Provincias, para fines de interés público, dando cuenta al Poder Legislativo para su aprobación y oportunamente conforme al artículo 107 de la Constitución Nacional. 7 - Representa a la Provincia en las relaciones oficiales con los poderes federales y demás autoridades nacionales y provinciales. 8 - Hace recaudar los impuestos y rentas de la Provincia y decreta su inversión con sujeción a las leyes de presupuesto y contabilidad, debiendo hacer publicar mensualmente el estado de la Tesorería. 9 - Nombra con acuerdo del Senado, o a propuesta de la Suprema Corte, a todos los funcionarios que esta Constitución determina, y por sí solo, a los funcionarios y empleados para los cuales la ley no establezca otra forma de nombramiento. 10 - Remueve los funcionarios y empleados de la administración cuyo nombramiento o remoción no están acordados a otro poder con arreglo a esta Constitución y a la ley. 11 - Prorroga las sesiones ordinarias de las Cámaras y convoca a extraordinarias en los casos previstos en esta Constitución. 12 - Organiza la Guardia Nacional de la Provincia con arreglo a las leyes militares de la Nación. 13 - Informa a las Cámaras con un mensaje escrito, a la apertura de sus sesiones, sobre el estado general de la administración. 14 - Presenta a la Legislatura el proyecto de ley de presupuesto para el año siguiente, acompañado del plan de recursos y da cuenta del uso y ejercicio del presupuesto anterior. 15 - Presta el auxilio de la fuerza pública, cuando le sea solicitado por los tribunales de justicia, autoridades y funcionarios que por la Constitución y la ley están autorizados para hacer uso de ella. 16 - Toma las medidas necesarias para conservar la paz y el orden público, por todos los medios que no estén expresamente prohibidos por la Constitución y leyes vigentes. 17 - Es el jefe de las milicias de la Provincia. 18 - Moviliza la milicia de uno o varios departamentos de la Provincia, durante el receso de las Cámaras, cuando un grave motivo de seguridad o de orden lo requiera, dando cuenta de ello, y aun estando en sesiones, podrá usar de las mismas atribuciones siempre que el caso no admita dilación, dando cuenta inmediatamente a las Cámaras y al Gobierno de la Nación. 19 - Tiene bajo su vigilancia la seguridad del territorio y de sus habitantes y la de las reparticiones y establecimientos públicos de la Provincia. 20 - Conoce y resuelve en los asuntos contenciosoadministrativos con arreglo a la ley. 21 - Provee en el receso de las Cámaras por medio de nombramientos en comisión que cesarán 30 días después de estar la Legislatura en funciones, las vacantes de empleos que requieren el acuerdo del Senado. 22 - Suspende o remueve a los funcionarios administrativos para cuyo nombramiento sea necesario el acuerdo del Senado, y llena interinamente sus puestos, debiendo darle cuenta del hecho inmediatamente de reunido, para que falle sobre la justicia de la medida, aprobándola o dejándola sin efecto; entendiéndose que no podrá desaprobarla sino con el voto de los dos tercios de los miembros presentes. 23 - Es agente inmediato y directo del Gobierno nacional para hacer cumplir en la Provincia la Constitución y las leyes de la Nación.`, currentText: `El gobernador es el jefe del Poder Ejecutivo y tiene las siguientes atribuciones y deberes: 1 - Tiene a su cargo la administración general de la Provincia. 2 - Participa en la formación de las leyes con arreglo a esta Constitución, las promulga y expide decretos, instrumentos o reglamentos para su ejecución, sin alterar su espíritu. 3 - Inicia leyes o propone la modificación o derogación de las existentes, por proyectos presentados a las Cámaras. 4 - Hace la convocatoria para las elecciones populares conforme a esta Constitución. 5 - Podrá indultar o conmutar las penas impuestas por delitos sujetos a la jurisdicción provincial, previo informe motivado de la Suprema Corte sobre la oportunidad y conveniencia del indulto o conmutación y con arreglo a la ley reglamentaria que determinará los casos y la forma en que pueda solicitarse. El gobernador no podrá ejercer esta atribución cuando se trate de delitos cometidos por funcionarios públicos en el ejercicio de sus funciones. 6 - Celebra y firma tratados parciales con las demás Provincias, para fines de interés público, dando cuenta al Poder Legislativo para su aprobación y oportunamente conforme al artículo 107 de la Constitución Nacional. 7 - Representa a la Provincia en las relaciones oficiales con los poderes federales y demás autoridades nacionales y provinciales. 8 - Hace recaudar los impuestos y rentas de la Provincia y decreta su inversión con sujeción a las leyes de presupuesto y contabilidad, debiendo hacer publicar mensualmente el estado de la Tesorería. 9 - Nombra con acuerdo del Senado, o a propuesta de la Suprema Corte, a todos los funcionarios que esta Constitución determina, y por sí solo, a los funcionarios y empleados para los cuales la ley no establezca otra forma de nombramiento. 10 - Remueve los funcionarios y empleados de la administración cuyo nombramiento o remoción no están acordados a otro poder con arreglo a esta Constitución y a la ley. 11 - Prorroga las sesiones ordinarias de las Cámaras y convoca a extraordinarias en los casos previstos en esta Constitución. 12 - Organiza la Guardia Nacional de la Provincia con arreglo a las leyes militares de la Nación. 13 - Informa a las Cámaras con un mensaje escrito, a la apertura de sus sesiones, sobre el estado general de la administración. 14 - Presenta a la Legislatura el proyecto de ley de presupuesto para el año siguiente, acompañado del plan de recursos y da cuenta del uso y ejercicio del presupuesto anterior. 15 - Presta el auxilio de la fuerza pública, cuando le sea solicitado por los tribunales de justicia, autoridades y funcionarios que por la Constitución y la ley están autorizados para hacer uso de ella. 16 - Toma las medidas necesarias para conservar la paz y el orden público, por todos los medios que no estén expresamente prohibidos por la Constitución y leyes vigentes. 17 - Es el jefe de las milicias de la Provincia. 18 - Moviliza la milicia de uno o varios departamentos de la Provincia, durante el receso de las Cámaras, cuando un grave motivo de seguridad o de orden lo requiera, dando cuenta de ello, y aun estando en sesiones, podrá usar de las mismas atribuciones siempre que el caso no admita dilación, dando cuenta inmediatamente a las Cámaras y al Gobierno de la Nación. 19 - Tiene bajo su vigilancia la seguridad del territorio y de sus habitantes y la de las reparticiones y establecimientos públicos de la Provincia. 20 - Conoce y resuelve en los asuntos contenciosoadministrativos con arreglo a la ley. 21 - Provee en el receso de las Cámaras por medio de nombramientos en comisión que cesarán 30 días después de estar la Legislatura en funciones, las vacantes de empleos que requieren el acuerdo del Senado. 22 - Suspende o remueve a los funcionarios administrativos para cuyo nombramiento sea necesario el acuerdo del Senado, y llena interinamente sus puestos, debiendo darle cuenta del hecho inmediatamente de reunido, para que falle sobre la justicia de la medida, aprobándola o dejándola sin efecto; entendiéndose que no podrá desaprobarla sino con el voto de los dos tercios de los miembros presentes. 23 - Es agente inmediato y directo del Gobierno nacional para hacer cumplir en la Provincia la Constitución y las leyes de la Nación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-129', lawId: 'const-mendoza', number: '129', title: '', originalText: `El gobernador no puede expedir resoluciones ni decretos sin la firma del ministro respectivo, con excepción del nombramiento y remoción de éstos.`, currentText: `El gobernador no puede expedir resoluciones ni decretos sin la firma del ministro respectivo, con excepción del nombramiento y remoción de éstos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-130', lawId: 'const-mendoza', number: '130', title: '', originalText: `Solo podrán decretarse erogaciones en acuerdo de ministros, durante el receso de la Legislatura, en los casos de los incisos 16 y 18 del art. 128 de esta Constitución y en aquellos de necesidad imperiosa e impostergable con cargo de dar cuenta a la Legislatura en sus primeras sesiones.`, currentText: `Solo podrán decretarse erogaciones en acuerdo de ministros, durante el receso de la Legislatura, en los casos de los incisos 16 y 18 del art. 128 de esta Constitución y en aquellos de necesidad imperiosa e impostergable con cargo de dar cuenta a la Legislatura en sus primeras sesiones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-131', lawId: 'const-mendoza', number: '131', title: '', originalText: `El despacho de los asuntos administrativos estará a cargo de tres o más ministros secretarios. Una ley fijará el número de ellos, así como las funciones y los ramos adscriptos al despacho respectivo.`, currentText: `El despacho de los asuntos administrativos estará a cargo de tres o más ministros secretarios. Una ley fijará el número de ellos, así como las funciones y los ramos adscriptos al despacho respectivo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-132', lawId: 'const-mendoza', number: '132', title: '', originalText: `Para ser nombrado ministro se requieren las condiciones que esta Constitución exige para ser elegido diputado.`, currentText: `Para ser nombrado ministro se requieren las condiciones que esta Constitución exige para ser elegido diputado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-133', lawId: 'const-mendoza', number: '133', title: '', originalText: `Los ministros despacharán de acuerdo con el gobernador y refrendarán con sus firmas los actos gubernativos, sin cuyo requisito no tendrán efecto ni se les dará cumplimiento. Podrán, no obstante, resolver por sí solos, en todo lo referente al régimen interno y disciplinario de sus respectivos departamentos y dictar providencias o resoluciones de trámite.`, currentText: `Los ministros despacharán de acuerdo con el gobernador y refrendarán con sus firmas los actos gubernativos, sin cuyo requisito no tendrán efecto ni se les dará cumplimiento. Podrán, no obstante, resolver por sí solos, en todo lo referente al régimen interno y disciplinario de sus respectivos departamentos y dictar providencias o resoluciones de trámite.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-134', lawId: 'const-mendoza', number: '134', title: '', originalText: `Son responsables de todas las resoluciones y órdenes que autoricen, sin que puedan eximirse de responsabilidad por haber procedido en virtud de orden del gobernador.`, currentText: `Son responsables de todas las resoluciones y órdenes que autoricen, sin que puedan eximirse de responsabilidad por haber procedido en virtud de orden del gobernador.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-135', lawId: 'const-mendoza', number: '135', title: '', originalText: `Los ministros podrán concurrir a todas las sesiones públicas y secretas de las Cámaras y tomar parte en sus deliberaciones; pero no tendrán voto. Sin embargo, no podrán concurrir a las sesiones que celebren las Cámaras para tratar de los asuntos a que se refieren los artículos 74, inciso 2), 87, 91, 97, 105 y 167 de esta Constitución y en los demás casos que son privativos de ellas.`, currentText: `Los ministros podrán concurrir a todas las sesiones públicas y secretas de las Cámaras y tomar parte en sus deliberaciones; pero no tendrán voto. Sin embargo, no podrán concurrir a las sesiones que celebren las Cámaras para tratar de los asuntos a que se refieren los artículos 74, inciso 2), 87, 91, 97, 105 y 167 de esta Constitución y en los demás casos que son privativos de ellas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-136', lawId: 'const-mendoza', number: '136', title: '', originalText: `Los ministros gozarán de un sueldo establecido por la ley, el cual podrá ser aumentado durante el período de sus nombramientos, con el voto de los dos tercios de los miembros de cada Cámara.`, currentText: `Los ministros gozarán de un sueldo establecido por la ley, el cual podrá ser aumentado durante el período de sus nombramientos, con el voto de los dos tercios de los miembros de cada Cámara.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-137', lawId: 'const-mendoza', number: '137', title: '', originalText: `Los ministros están obligados a remitir a cualquiera de las Cámaras, los informes, memorias, etcétera, que éstas les soliciten sobre lo relativo a los asuntos de sus respectivos departamentos.`, currentText: `Los ministros están obligados a remitir a cualquiera de las Cámaras, los informes, memorias, etcétera, que éstas les soliciten sobre lo relativo a los asuntos de sus respectivos departamentos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-138', lawId: 'const-mendoza', number: '138', title: '', originalText: `El contador y tesorero de la Provincia serán nombrados por el gobernador con acuerdo del Senado.`, currentText: `El contador y tesorero de la Provincia serán nombrados por el gobernador con acuerdo del Senado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-139', lawId: 'const-mendoza', number: '139', title: '', originalText: `El contador observará todas las órdenes de pago que no estén arregladas a la ley general de presupuesto o leyes especiales o a los acuerdos del Poder Ejecutivo dictados en los casos del artículo 130.`, currentText: `El contador observará todas las órdenes de pago que no estén arregladas a la ley general de presupuesto o leyes especiales o a los acuerdos del Poder Ejecutivo dictados en los casos del artículo 130.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-140', lawId: 'const-mendoza', number: '140', title: '', originalText: `El tesorero no podrá ejecutar pago que no haya sido previamente autorizado por el contador, con arreglo a lo que dispone el artículo anterior. En caso de contravención, el tesorero y el contador responderán personalmente.`, currentText: `El tesorero no podrá ejecutar pago que no haya sido previamente autorizado por el contador, con arreglo a lo que dispone el artículo anterior. En caso de contravención, el tesorero y el contador responderán personalmente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-141', lawId: 'const-mendoza', number: '141', title: '', originalText: `La ley de contabilidad determinará las calidades del contador y tesoreros, las causas por que pueden ser removidos y las responsabilidades a que están sujetos.`, currentText: `La ley de contabilidad determinará las calidades del contador y tesoreros, las causas por que pueden ser removidos y las responsabilidades a que están sujetos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-142', lawId: 'const-mendoza', number: '142', title: '', originalText: `El Poder Judicial de la Provincia será ejercido por una Suprema Corte, cámaras de apelaciones, jueces de primera instancia y demás juzgados, tribunales y funcionarios inferiores creados por ley.`, currentText: `El Poder Judicial de la Provincia será ejercido por una Suprema Corte, cámaras de apelaciones, jueces de primera instancia y demás juzgados, tribunales y funcionarios inferiores creados por ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-143', lawId: 'const-mendoza', number: '143', title: '', originalText: `La Suprema Corte de Justicia se compondrá de 7 miembros por los menos y habrá un procurador para ella, pudiendo dividirse en salas para conocer en los recursos determinados por esta Constitución y la ley. La composición de los restantes tribunales indicados en el artículo anterior, será fijada también por la ley. Las antiguedades profesionales requeridas por los arts. 152 a 155 de esta Constitución, para ser magistrados o funcionarios del Poder Judicial, salvo el caso de los nativos de la Provincia, deben referirse al ejercicio de la abogacía o a servicios prestados en la magistratura local.`, currentText: `La Suprema Corte de Justicia se compondrá de 7 miembros por los menos y habrá un procurador para ella, pudiendo dividirse en salas para conocer en los recursos determinados por esta Constitución y la ley. La composición de los restantes tribunales indicados en el artículo anterior, será fijada también por la ley. Las antiguedades profesionales requeridas por los arts. 152 a 155 de esta Constitución, para ser magistrados o funcionarios del Poder Judicial, salvo el caso de los nativos de la Provincia, deben referirse al ejercicio de la abogacía o a servicios prestados en la magistratura local.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-144', lawId: 'const-mendoza', number: '144', title: '', originalText: `La Suprema Corte tendrá las siguientes atribuciones y deberes, sin perjuicio de los demás que determine la ley: 1 - La superintendencia sobre toda la administración de justicia y la facultad de establecer correcciones y medidas disciplinarias que considere conveniente de acuerdo con la ley, dictando su reglamento interno y el de todas las oficinas del Poder Judicial. 2 - Debe pasar anualmente a la Legislatura y al Poder Ejecutivo, una memoria sobre el movimiento y estado de la administración de justicia, y podrá proponer proyectos de reforma del procedimiento y organización que sean compatibles con esta Constitución. 3 - Ejerce jurisdicción originaria y de apelación para conocer y resolver sobre la constitucionalidad o inconstitucionalidadde leyes, decretos, ordenanzas, resoluciones o reglamentos que estatuyan sobre materia regida por ésta Constitución y se controviertan por parte interesada. 4 - Conoce y resuelve originariamente en las causas y competencia entre los poderes públicos de la Provincia y en los conflictos internos entre las diversas ramas de éstos, y en las que se susciten entre los tribunales de justicia con motivo de su respectiva jurisdicción. 5 - Decide las causas contencioso administrativas en única instancia, previa denegación expresa o tácita de la autoridad administrativa competente al reconocimiento de los derechos gestionados por parte interesada. Se entenderá que hay denegación tácita por la autoridad administrativa, cuando no se resolviera definitivamente, dentro de los 60 días de estar el expediente en estado de sentencia. 6 - Conoce en grado de apelación o en consulta, en tribunal pleno, de las causas en que se impone la pena capital, siendo necesario el voto unánime de sus miembros para confirmar la sentencia condenatoria. 7 - Conoce privadamente de los casos de reducción de pena, autorizados por el Código Penal. 8 - Ejerce jurisdicción exclusiva en el régimen interno de las cárceles de detenidos. 9 - Conocerá como tribunal de revisión en los casos en que después de pronunciada la sentencia definitiva de segunda instancia, la parte perjudicada obtuviere o recobrare documentos decisivos, ignorados, extraviados o detenidos por fuerza mayor, por obra de la parte en cuyo favor se hubiere dictado la sentencia o por otra causa análoga; cuando la sentencia se hubiere dictado en virtud de documentos o de prueba testimonial y se declarase en juicio posterior que fueron falsas dichas pruebas o documentos; cuando la sentencia firme recayese sobre cosas no pedidas por las partes u omitiese resolver sobre alguno de los capítulos de la demanda, contestación o reconvención; y cuando la sentencia firme se hubiere dictado u obtenido en virtud de prevaricato, cohecho, violencia u otra maquinación fraudulenta. 10 - Hará todos los nombramientos de los empleados inferiores del Poder Judicial con arreglo a la ley. 11 - Será competente para enjuiciar, suspender o separar de sus cargos a los empleados inferiores del Poder Judicial, por delitos o faltas cometidas en el ejercicio de sus funciones o por incapacidad. En estos casos, cuando resultasen comprobados delitos o faltas punibles por ley, remitirá los antecedentes a la justicia criminal para el proceso correspondiente. 12 - Formará la matrícula de abogados, escribanos, procuradores y peritos judiciales con arreglo de la ley. 13 - Conoce del recurso de queja por denegación o retardo de justicia de los tribunales y jueces de la Provincia, con sujeción a la forma y trámite que la ley de procedimientos establezca.`, currentText: `La Suprema Corte tendrá las siguientes atribuciones y deberes, sin perjuicio de los demás que determine la ley: 1 - La superintendencia sobre toda la administración de justicia y la facultad de establecer correcciones y medidas disciplinarias que considere conveniente de acuerdo con la ley, dictando su reglamento interno y el de todas las oficinas del Poder Judicial. 2 - Debe pasar anualmente a la Legislatura y al Poder Ejecutivo, una memoria sobre el movimiento y estado de la administración de justicia, y podrá proponer proyectos de reforma del procedimiento y organización que sean compatibles con esta Constitución. 3 - Ejerce jurisdicción originaria y de apelación para conocer y resolver sobre la constitucionalidad o inconstitucionalidadde leyes, decretos, ordenanzas, resoluciones o reglamentos que estatuyan sobre materia regida por ésta Constitución y se controviertan por parte interesada. 4 - Conoce y resuelve originariamente en las causas y competencia entre los poderes públicos de la Provincia y en los conflictos internos entre las diversas ramas de éstos, y en las que se susciten entre los tribunales de justicia con motivo de su respectiva jurisdicción. 5 - Decide las causas contencioso administrativas en única instancia, previa denegación expresa o tácita de la autoridad administrativa competente al reconocimiento de los derechos gestionados por parte interesada. Se entenderá que hay denegación tácita por la autoridad administrativa, cuando no se resolviera definitivamente, dentro de los 60 días de estar el expediente en estado de sentencia. 6 - Conoce en grado de apelación o en consulta, en tribunal pleno, de las causas en que se impone la pena capital, siendo necesario el voto unánime de sus miembros para confirmar la sentencia condenatoria. 7 - Conoce privadamente de los casos de reducción de pena, autorizados por el Código Penal. 8 - Ejerce jurisdicción exclusiva en el régimen interno de las cárceles de detenidos. 9 - Conocerá como tribunal de revisión en los casos en que después de pronunciada la sentencia definitiva de segunda instancia, la parte perjudicada obtuviere o recobrare documentos decisivos, ignorados, extraviados o detenidos por fuerza mayor, por obra de la parte en cuyo favor se hubiere dictado la sentencia o por otra causa análoga; cuando la sentencia se hubiere dictado en virtud de documentos o de prueba testimonial y se declarase en juicio posterior que fueron falsas dichas pruebas o documentos; cuando la sentencia firme recayese sobre cosas no pedidas por las partes u omitiese resolver sobre alguno de los capítulos de la demanda, contestación o reconvención; y cuando la sentencia firme se hubiere dictado u obtenido en virtud de prevaricato, cohecho, violencia u otra maquinación fraudulenta. 10 - Hará todos los nombramientos de los empleados inferiores del Poder Judicial con arreglo a la ley. 11 - Será competente para enjuiciar, suspender o separar de sus cargos a los empleados inferiores del Poder Judicial, por delitos o faltas cometidas en el ejercicio de sus funciones o por incapacidad. En estos casos, cuando resultasen comprobados delitos o faltas punibles por ley, remitirá los antecedentes a la justicia criminal para el proceso correspondiente. 12 - Formará la matrícula de abogados, escribanos, procuradores y peritos judiciales con arreglo de la ley. 13 - Conoce del recurso de queja por denegación o retardo de justicia de los tribunales y jueces de la Provincia, con sujeción a la forma y trámite que la ley de procedimientos establezca.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-145', lawId: 'const-mendoza', number: '145', title: '', originalText: `La Ley Orgánica de Tribunales determinará su ubicación, su número y su jurisdicción territorial, como asimismo las materias de su competencia.`, currentText: `La Ley Orgánica de Tribunales determinará su ubicación, su número y su jurisdicción territorial, como asimismo las materias de su competencia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-146', lawId: 'const-mendoza', number: '146', title: '', originalText: `Los procedimientos ante todos los tribunales de la Provincia serán públicos, salvo los casos en que la publicidad afecte la moral, la seguridad o el orden social.`, currentText: `Los procedimientos ante todos los tribunales de la Provincia serán públicos, salvo los casos en que la publicidad afecte la moral, la seguridad o el orden social.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-147', lawId: 'const-mendoza', number: '147', title: '', originalText: `Queda establecida ante todos los tribunales de la Provincia la libre defensa en causa propia y libre representación, con las restricciones que establezca la ley de la materia.`, currentText: `Queda establecida ante todos los tribunales de la Provincia la libre defensa en causa propia y libre representación, con las restricciones que establezca la ley de la materia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-148', lawId: 'const-mendoza', number: '148', title: '', originalText: `Los tribunales y jueces deben resolver siempre según la ley, y en el ejercicio de sus funciones procederán aplicando la Constitución, las leyes y tratados nacionales como ley suprema en todos los casos, y la Constitución de la Provincia como ley suprema respecto de las leyes que haya sancionado o sancionare la Legislatura.`, currentText: `Los tribunales y jueces deben resolver siempre según la ley, y en el ejercicio de sus funciones procederán aplicando la Constitución, las leyes y tratados nacionales como ley suprema en todos los casos, y la Constitución de la Provincia como ley suprema respecto de las leyes que haya sancionado o sancionare la Legislatura.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-149', lawId: 'const-mendoza', number: '149', title: '', originalText: `Las sentencias que pronuncien los tribunales y jueces letrados se fundarán en el texto expreso de la ley, y a falta de ésta, en los principios jurídicos de la legislación vigente en la materia respectiva, y en defecto de éstos, en los principios generales del derecho, teniendo en consideración las circunstancias del caso.`, currentText: `Las sentencias que pronuncien los tribunales y jueces letrados se fundarán en el texto expreso de la ley, y a falta de ésta, en los principios jurídicos de la legislación vigente en la materia respectiva, y en defecto de éstos, en los principios generales del derecho, teniendo en consideración las circunstancias del caso.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-150', lawId: 'const-mendoza', number: '150', title: '', originalText: `Los miembros de la suprema corte de justicia y su procurador general, serán nombrados por el poder ejecutivo con el acuerdo del senado.Los jueces de los tribunales inferiores y los representantes del Ministerio Público, serán propuestos por el consejo de la magistratura al poder ejecutivo y designados por este con acuerdo del H. Senado. El consejo estará integrado por un miembro de la suprema corte de justicia, quien lo presidirá; un representante del poder ejecutivo; un representante de los magistrados en ejercicio; dos abogados de la matricula de diferente circunscripción judicial y dos diputados provinciales de distintos partidos políticos. Conjuntamente serán elegidos igual numero de miembros suplentes, que reemplazaran a los titulares ante cualquier circunstancia que les impida asistir a las sesiones del consejo, o en los supuestos de excusación o recusación con causa que la Ley establezca. Los representantes de la Suprema Corte de Justicia, del poder ejecutivo y los diputados provinciales, serán designados y removidos por sus representados. Cualquier ciudadano podrá requerir su remoción, ante quien los designo, por las causales establecidas en el articulo 109. Los representantes de los magistrados y de los abogados serán elegidos por el voto directo de sus pares y podrán ser removidos a pedido de cualquier ciudadano, por las causales enumeradas en el apartado anterior, en la forma prevista en los artículos 164 y siguientes de esta Constitución. Los miembros del consejo duraran dos años en sus funciones pudiendo ser reelectos con intervalo de un periodo. El desempeño del cargo de miembro del consejo de la magistratura tendrá carácter honorario y no le será aplicable lo dispuesto en el articulo 151. El consejo de la magistratura tendrá las siguientes atribuciones: 1) Proponer al poder ejecutivo, en ternas vinculantes, el nombramiento de jueces y representantes del misterio publico, con excepción de los miembros de la suprema corte de justicia y su procurador general. 2) Seleccionar mediante concursos públicos, los postulantes a los cargos referidos en el apartado anterior. El consejo tomara todas sus decisiones por mayoría absoluta de votos de la totalidad de sus miembros.`, currentText: `Los miembros de la suprema corte de justicia y su procurador general, serán nombrados por el poder ejecutivo con el acuerdo del senado.Los jueces de los tribunales inferiores y los representantes del Ministerio Público, serán propuestos por el consejo de la magistratura al poder ejecutivo y designados por este con acuerdo del H. Senado. El consejo estará integrado por un miembro de la suprema corte de justicia, quien lo presidirá; un representante del poder ejecutivo; un representante de los magistrados en ejercicio; dos abogados de la matricula de diferente circunscripción judicial y dos diputados provinciales de distintos partidos políticos. Conjuntamente serán elegidos igual numero de miembros suplentes, que reemplazaran a los titulares ante cualquier circunstancia que les impida asistir a las sesiones del consejo, o en los supuestos de excusación o recusación con causa que la Ley establezca. Los representantes de la Suprema Corte de Justicia, del poder ejecutivo y los diputados provinciales, serán designados y removidos por sus representados. Cualquier ciudadano podrá requerir su remoción, ante quien los designo, por las causales establecidas en el articulo 109. Los representantes de los magistrados y de los abogados serán elegidos por el voto directo de sus pares y podrán ser removidos a pedido de cualquier ciudadano, por las causales enumeradas en el apartado anterior, en la forma prevista en los artículos 164 y siguientes de esta Constitución. Los miembros del consejo duraran dos años en sus funciones pudiendo ser reelectos con intervalo de un periodo. El desempeño del cargo de miembro del consejo de la magistratura tendrá carácter honorario y no le será aplicable lo dispuesto en el articulo 151. El consejo de la magistratura tendrá las siguientes atribuciones: 1) Proponer al poder ejecutivo, en ternas vinculantes, el nombramiento de jueces y representantes del misterio publico, con excepción de los miembros de la suprema corte de justicia y su procurador general. 2) Seleccionar mediante concursos públicos, los postulantes a los cargos referidos en el apartado anterior. El consejo tomara todas sus decisiones por mayoría absoluta de votos de la totalidad de sus miembros.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-151', lawId: 'const-mendoza', number: '151', title: '', originalText: `Los funcionarios a que se refiere el artículo anterior serán inamovibles mientras dure su buena conducta. Gozarán de una retribución que se fijará por ley y no podrá ser disminuida mientras permanezcan en funciones. En ningún caso esta garantía de intangibilidad comprenderá la actualización monetaria de sus remuneraciones mediante índices de precios y/o cualquier otro mecanismo de ajuste, ni la exención de los aportes que con fines de previsión u obra social se establezcan con carácter general.`, currentText: `Los funcionarios a que se refiere el artículo anterior serán inamovibles mientras dure su buena conducta. Gozarán de una retribución que se fijará por ley y no podrá ser disminuida mientras permanezcan en funciones. En ningún caso esta garantía de intangibilidad comprenderá la actualización monetaria de sus remuneraciones mediante índices de precios y/o cualquier otro mecanismo de ajuste, ni la exención de los aportes que con fines de previsión u obra social se establezcan con carácter general.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-152', lawId: 'const-mendoza', number: '152', title: '', originalText: `Para ser miembro de la Suprema Corte y procurador de ella se requiere: 1 - Haber nacido en territorio argentino o ser hijos de padres nativos, habiendo optado por la ciudadanía de sus padres, si hubiere nacido en territorio extranjero. 2 - Haber cumplido 30 años de edad y no tener más de 70. 3 - Ser abogado con título de universidad nacional y con 10 años de ejercicio de la profesión u 8 de magistratura.`, currentText: `Para ser miembro de la Suprema Corte y procurador de ella se requiere: 1 - Haber nacido en territorio argentino o ser hijos de padres nativos, habiendo optado por la ciudadanía de sus padres, si hubiere nacido en territorio extranjero. 2 - Haber cumplido 30 años de edad y no tener más de 70. 3 - Ser abogado con título de universidad nacional y con 10 años de ejercicio de la profesión u 8 de magistratura.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-153', lawId: 'const-mendoza', number: '153', title: '', originalText: `Para ser miembro de las Cámaras de apelaciones, de los tribunales colegiados de única instancia y fiscal de ellos, se requiere: 1 - Ciudadanía en ejercicio. 2 - Haber cumplido 28 años y no tener más de 65. 3 - Ser abogado con título universitario de facultad nacional, con 8 años de ejercicio en la profesión o 5 en la magistratura, habiendo ejercido la profesión durante 5 años o algún cargo en la magistratura durante 2 años, para el que se requiera la calidad de abogado.`, currentText: `Para ser miembro de las Cámaras de apelaciones, de los tribunales colegiados de única instancia y fiscal de ellos, se requiere: 1 - Ciudadanía en ejercicio. 2 - Haber cumplido 28 años y no tener más de 65. 3 - Ser abogado con título universitario de facultad nacional, con 8 años de ejercicio en la profesión o 5 en la magistratura, habiendo ejercido la profesión durante 5 años o algún cargo en la magistratura durante 2 años, para el que se requiera la calidad de abogado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-154', lawId: 'const-mendoza', number: '154', title: '', originalText: `Para ser juez letrado en primera instancia, se requiere: 1 - Ciudadanía en ejercicio. 2 - Tener más de 25 años y menos de 70. 3 - Ser abogado con título universitario de facultad nacional, habiendo ejercido la profesión durante 5 años o algún cargo en la magistratura durante 2 años, para el que se requiere la calidad de abogado.`, currentText: `Para ser juez letrado en primera instancia, se requiere: 1 - Ciudadanía en ejercicio. 2 - Tener más de 25 años y menos de 70. 3 - Ser abogado con título universitario de facultad nacional, habiendo ejercido la profesión durante 5 años o algún cargo en la magistratura durante 2 años, para el que se requiere la calidad de abogado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-155', lawId: 'const-mendoza', number: '155', title: '', originalText: `Para se fiscal de primera instancia, asesor de menores, defensor de pobres y ausentes y juez de paz letrado se requiere: ciudadanía en ejercicio, título de abogado de facultad nacional y un año de ejercicio en la profesión o empleo en la magistratura, para el que se requiere la calidad de abogado.`, currentText: `Para se fiscal de primera instancia, asesor de menores, defensor de pobres y ausentes y juez de paz letrado se requiere: ciudadanía en ejercicio, título de abogado de facultad nacional y un año de ejercicio en la profesión o empleo en la magistratura, para el que se requiere la calidad de abogado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-156', lawId: 'const-mendoza', number: '156', title: '', originalText: `La presidencia de la Suprema Corte y de las cámaras de apelaciones, se turnará entre sus miembros en la forma que la ley determine.`, currentText: `La presidencia de la Suprema Corte y de las cámaras de apelaciones, se turnará entre sus miembros en la forma que la ley determine.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-157', lawId: 'const-mendoza', number: '157', title: '', originalText: `Los miembros de la Suprema Corte prestarán juramento por Dios y la Patria o por la Patria y por su honor, ante el Poder Ejecutivo, de desempeñar fielmente su cargo. Los de las Cámaras y demás miembros del Poder Judicial, prestarán igual juramento ante la Suprema Corte.`, currentText: `Los miembros de la Suprema Corte prestarán juramento por Dios y la Patria o por la Patria y por su honor, ante el Poder Ejecutivo, de desempeñar fielmente su cargo. Los de las Cámaras y demás miembros del Poder Judicial, prestarán igual juramento ante la Suprema Corte.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-158', lawId: 'const-mendoza', number: '158', title: '', originalText: `Los miembros del Poder Judicial serán personalmente recusables por las causales que fijará la ley.`, currentText: `Los miembros del Poder Judicial serán personalmente recusables por las causales que fijará la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-159', lawId: 'const-mendoza', number: '159', title: '', originalText: `Corresponde a la Suprema Corte, cámaras de apelaciones y juzgados de primera instancia, el conocimiento y decisión de las causas que se susciten en la Provincia, sin más excepciones que las que fluyen de la Constitución y leyes nacionales y de esta Constitución`, currentText: `Corresponde a la Suprema Corte, cámaras de apelaciones y juzgados de primera instancia, el conocimiento y decisión de las causas que se susciten en la Provincia, sin más excepciones que las que fluyen de la Constitución y leyes nacionales y de esta Constitución`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-160', lawId: 'const-mendoza', number: '160', title: '', originalText: `Para el pronunciamiento de las sentencias definitivas, los jueces y tribunales establecerán las cuestiones de hecho y en seguida las de derecho sometidas a su decisión.`, currentText: `Para el pronunciamiento de las sentencias definitivas, los jueces y tribunales establecerán las cuestiones de hecho y en seguida las de derecho sometidas a su decisión.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-161', lawId: 'const-mendoza', number: '161', title: '', originalText: `Todo juicio o recurso debe ser fallado por la Suprema Corte, tribunales o juzgados, en los términos que fije la ley de procedimientos. En caso de infracción, sin causa legalmente justificada, los magistrados que contravinieren a esta prescripción, son responsables no sólo de los perjuicios que causen a las partes, sino del mal desempeño de sus funciones. Un número reiterado de estas infracciones, que determinará la ley, será considerado como mal desempeño de sus funciones y podrá motivar el juicio de remoción contra el respectivo funcionario.`, currentText: `Todo juicio o recurso debe ser fallado por la Suprema Corte, tribunales o juzgados, en los términos que fije la ley de procedimientos. En caso de infracción, sin causa legalmente justificada, los magistrados que contravinieren a esta prescripción, son responsables no sólo de los perjuicios que causen a las partes, sino del mal desempeño de sus funciones. Un número reiterado de estas infracciones, que determinará la ley, será considerado como mal desempeño de sus funciones y podrá motivar el juicio de remoción contra el respectivo funcionario.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-162', lawId: 'const-mendoza', number: '162', title: '', originalText: `En las causas contencioso-administrativas, la Suprema Corte tendrá facultad de mandar cumplir directamente sus sentencias por las oficinas o empleados respectivos, si la autoridad administrativa no lo hiciese dentro de los 60 días de notificada la sentencia, salvo lo dispuesto en el artículo 40 de esta Constitución. Los empleados a que alude este artículo serán responsables por la falta de cumplimiento de las disposiciones de la Suprema Corte.`, currentText: `En las causas contencioso-administrativas, la Suprema Corte tendrá facultad de mandar cumplir directamente sus sentencias por las oficinas o empleados respectivos, si la autoridad administrativa no lo hiciese dentro de los 60 días de notificada la sentencia, salvo lo dispuesto en el artículo 40 de esta Constitución. Los empleados a que alude este artículo serán responsables por la falta de cumplimiento de las disposiciones de la Suprema Corte.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-163', lawId: 'const-mendoza', number: '163', title: '', originalText: `Los miembros de la Suprema Corte y el procurador de ella serán enjuiciables en la misma forma que el gobernador de la Provincia y pueden ser acusados por cualquier habitante de ésta, que goce de la plenitud de sus derechos civiles.`, currentText: `Los miembros de la Suprema Corte y el procurador de ella serán enjuiciables en la misma forma que el gobernador de la Provincia y pueden ser acusados por cualquier habitante de ésta, que goce de la plenitud de sus derechos civiles.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-164', lawId: 'const-mendoza', number: '164', title: '', originalText: `Los jueces de las Cámaras de apelaciones, los de primera instancia, los fiscales, asesores y defensores, pueden ser acusados por las mismas causas a que se refiere el artículo 109, ante un Jury de Enjuiciamiento compuesto de los miembros de la Suprema Corte y un número igual de senadores y un número también igual de diputados que serán nombrados anualmente por votación nominal en la primera sesión que celebren las respectivas Cámaras. Este Jury será presidido por el presidente de la Suprema Corte o por su reemplazante legal y no podrá funcionar con menos de la mitad más uno de sus miembros. En caso de empate decidirá el presidente del Jury, aun cuando ya hubiese votado al pronunciarse el fallo.`, currentText: `Los jueces de las Cámaras de apelaciones, los de primera instancia, los fiscales, asesores y defensores, pueden ser acusados por las mismas causas a que se refiere el artículo 109, ante un Jury de Enjuiciamiento compuesto de los miembros de la Suprema Corte y un número igual de senadores y un número también igual de diputados que serán nombrados anualmente por votación nominal en la primera sesión que celebren las respectivas Cámaras. Este Jury será presidido por el presidente de la Suprema Corte o por su reemplazante legal y no podrá funcionar con menos de la mitad más uno de sus miembros. En caso de empate decidirá el presidente del Jury, aun cuando ya hubiese votado al pronunciarse el fallo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-165', lawId: 'const-mendoza', number: '165', title: '', originalText: `La acusación será presentada al presidente del Jury, quien deberá citar a los demás miembros que los componen, dentro de las 48 horas, observando las siguientes reglas que la Legislatura podrá ampliar, por medio de una ley reglamentaria, pero sin restringirlas ni alterarlas: 1 - La acusación se hará por escrito, determinando con toda precisión los hechos que le sirven de fundamento. 2 - El presidente del Jury, dará traslado al acusado por el término de 10 días, dándole copia de la acusación y de los documentos que la instruyan. Contestada la acusación o en rebeldía del acusado, si no hubiera contestado dentro del término establecido, el Jury decidirá por votación nominal y por mayoría de votos de la totalidad de sus miembros, si procede la continuación del juicio o si debe desestimarse la acusación. En el primer caso, el juicio se abrirá a prueba por el término de 30 días y el acusado quedará suspendido en el ejercicio de sus funciones. 3 - Desde el momento en que el Jury declare que procede la acusación, intervendrá el procurador de la corte en representación del ministerio público y sin perjuicio de la participación del acusador particular. 4 - Los miembros del Jury no son recusables, pero el acusado tendrá derecho a recusar sin causa a uno de ellos. 5 - En este juicio las partes podrán hacer uso de todos los medios de prueba admitidos por la ley. 6 - El acusado podrá comparecer por sí o por apoderado y si no compareciese será juzgado en rebeldía. 7 - Se garantiza en este juicio la libre defensa y la libre representación. 8 - Concluido el proceso, el Jury discutirá en sesión secreta, el mérito de la prueba y terminada esta discusión, se designará día para pronunciar en sesión pública, el veredicto definitivo, lo que se efectuará por votación nominal, sobre cada cargo, por sí o por no. 9 - Ningún acusado podrá ser declarado culpable por menos de la mayoría absoluta de los miembros que componen el Jury. 10 - El fallo condenatorio no tendrá más efecto que la destitución del acusado, salvo el caso de que el motivo de la condenatoria fuere la perpetración de delitos, que estuvieren sujetos a la justicia ordinaria, en cuyo caso el Jury deberá pasar los antecedentes al ministerio fiscal. 11 - Declarado absuelto el acusado, quedará ipso facto restablecido en la posesión de su empleo y a salvo las acciones civiles o criminales a que hubiere lugar.`, currentText: `La acusación será presentada al presidente del Jury, quien deberá citar a los demás miembros que los componen, dentro de las 48 horas, observando las siguientes reglas que la Legislatura podrá ampliar, por medio de una ley reglamentaria, pero sin restringirlas ni alterarlas: 1 - La acusación se hará por escrito, determinando con toda precisión los hechos que le sirven de fundamento. 2 - El presidente del Jury, dará traslado al acusado por el término de 10 días, dándole copia de la acusación y de los documentos que la instruyan. Contestada la acusación o en rebeldía del acusado, si no hubiera contestado dentro del término establecido, el Jury decidirá por votación nominal y por mayoría de votos de la totalidad de sus miembros, si procede la continuación del juicio o si debe desestimarse la acusación. En el primer caso, el juicio se abrirá a prueba por el término de 30 días y el acusado quedará suspendido en el ejercicio de sus funciones. 3 - Desde el momento en que el Jury declare que procede la acusación, intervendrá el procurador de la corte en representación del ministerio público y sin perjuicio de la participación del acusador particular. 4 - Los miembros del Jury no son recusables, pero el acusado tendrá derecho a recusar sin causa a uno de ellos. 5 - En este juicio las partes podrán hacer uso de todos los medios de prueba admitidos por la ley. 6 - El acusado podrá comparecer por sí o por apoderado y si no compareciese será juzgado en rebeldía. 7 - Se garantiza en este juicio la libre defensa y la libre representación. 8 - Concluido el proceso, el Jury discutirá en sesión secreta, el mérito de la prueba y terminada esta discusión, se designará día para pronunciar en sesión pública, el veredicto definitivo, lo que se efectuará por votación nominal, sobre cada cargo, por sí o por no. 9 - Ningún acusado podrá ser declarado culpable por menos de la mayoría absoluta de los miembros que componen el Jury. 10 - El fallo condenatorio no tendrá más efecto que la destitución del acusado, salvo el caso de que el motivo de la condenatoria fuere la perpetración de delitos, que estuvieren sujetos a la justicia ordinaria, en cuyo caso el Jury deberá pasar los antecedentes al ministerio fiscal. 11 - Declarado absuelto el acusado, quedará ipso facto restablecido en la posesión de su empleo y a salvo las acciones civiles o criminales a que hubiere lugar.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-166', lawId: 'const-mendoza', number: '166', title: '', originalText: `La absolución de un funcionario, por fallo de la Legislatura o del Jury de enjuiciamiento, no impedirá las acusaciones o acciones que por delitos puedan instaurarse ante los tribunales ordinarios, ni será en modo alguno, requisito previo para ejercitarlas antes o después de cesar en sus funciones.`, currentText: `La absolución de un funcionario, por fallo de la Legislatura o del Jury de enjuiciamiento, no impedirá las acusaciones o acciones que por delitos puedan instaurarse ante los tribunales ordinarios, ni será en modo alguno, requisito previo para ejercitarlas antes o después de cesar en sus funciones.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-167', lawId: 'const-mendoza', number: '167', title: '', originalText: `Producida acusación por delitos comunes, contra un miembro de la Legislatura o contra cualquiera de los funcionarios sujetos a juicio político ante la Legislatura o ante el Jury de Enjuiciamiento y existiendo mérito bastante en las constancias del proceso para decretar la prisión preventiva, comunicados los antecedentes a petición de parte, a instancia fiscal o de oficio por el juez, a la Cámara legislativa a que pertenezca el acusado, a la Cámara de Diputados o al Jury, en los respectivos casos, deberá procederse al desafuero o a la suspensión del acusado, a los efectos de la substanciación formal de la causa, proveyéndose la acefalía con arreglo a esta Constitución y a la ley. No podrá allanarse la inmunidad ni resolverse el desafuero sino por el voto de la mitad más uno de los miembros que componen la Cámara respectiva, o la Cámara de Diputados, o el Jury.`, currentText: `Producida acusación por delitos comunes, contra un miembro de la Legislatura o contra cualquiera de los funcionarios sujetos a juicio político ante la Legislatura o ante el Jury de Enjuiciamiento y existiendo mérito bastante en las constancias del proceso para decretar la prisión preventiva, comunicados los antecedentes a petición de parte, a instancia fiscal o de oficio por el juez, a la Cámara legislativa a que pertenezca el acusado, a la Cámara de Diputados o al Jury, en los respectivos casos, deberá procederse al desafuero o a la suspensión del acusado, a los efectos de la substanciación formal de la causa, proveyéndose la acefalía con arreglo a esta Constitución y a la ley. No podrá allanarse la inmunidad ni resolverse el desafuero sino por el voto de la mitad más uno de los miembros que componen la Cámara respectiva, o la Cámara de Diputados, o el Jury.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-168', lawId: 'const-mendoza', number: '168', title: '', originalText: `Si el desafuero no se produjera contra un miembro de la Legislatura o contra uno de los funcionarios acusables ante ésta o ante el Jury de Enjuiciamiento, la acción de los tribunales se paralizará temporariamente contra sus personas, suspendiéndose los términos para continuar el juicio una vez terminado el mandato del funcionario. El pedido del desafuero podrá repetirse por la autoridad competente, cada vez que se produzcan nuevas pruebas contra el acusado.`, currentText: `Si el desafuero no se produjera contra un miembro de la Legislatura o contra uno de los funcionarios acusables ante ésta o ante el Jury de Enjuiciamiento, la acción de los tribunales se paralizará temporariamente contra sus personas, suspendiéndose los términos para continuar el juicio una vez terminado el mandato del funcionario. El pedido del desafuero podrá repetirse por la autoridad competente, cada vez que se produzcan nuevas pruebas contra el acusado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-169', lawId: 'const-mendoza', number: '169', title: '', originalText: `No podrán los funcionarios judiciales intervenir en política en forma alguna, directa ni indirectamente, salvo la emisión del voto; ni ejecutar o participar en actos que afecten su circunspección y la imparcialidad de sus funciones o las menoscaben en público o en privado del buen concepto que debe rodear su persona y el cargo que desempeñan.`, currentText: `No podrán los funcionarios judiciales intervenir en política en forma alguna, directa ni indirectamente, salvo la emisión del voto; ni ejecutar o participar en actos que afecten su circunspección y la imparcialidad de sus funciones o las menoscaben en público o en privado del buen concepto que debe rodear su persona y el cargo que desempeñan.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-170', lawId: 'const-mendoza', number: '170', title: '', originalText: `En ningún caso el gobernador ni funcionario alguno ajeno al Poder Judicial, podrán ejercer funciones judiciales, arrogarse el conocimiento de causas pendientes, ni restablecer las fenecidas.`, currentText: `En ningún caso el gobernador ni funcionario alguno ajeno al Poder Judicial, podrán ejercer funciones judiciales, arrogarse el conocimiento de causas pendientes, ni restablecer las fenecidas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-171', lawId: 'const-mendoza', number: '171', title: '', originalText: `La Suprema Corte propondrá al Poder Ejecutivo el presupuesto anual de gastos de la administración de justicia, un mes antes de la época en que deba ser remitido a la Legislatura el presupuesto general de la administración.`, currentText: `La Suprema Corte propondrá al Poder Ejecutivo el presupuesto anual de gastos de la administración de justicia, un mes antes de la época en que deba ser remitido a la Legislatura el presupuesto general de la administración.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-172', lawId: 'const-mendoza', number: '172', title: '', originalText: `Todos los funcionarios sujetos a juicio político por esta Constitución, que formen parte de los poderes Ejecutivos y Judicial, gozarán de las mismas inmunidades que los miembros del Poder Legislativo.`, currentText: `Todos los funcionarios sujetos a juicio político por esta Constitución, que formen parte de los poderes Ejecutivos y Judicial, gozarán de las mismas inmunidades que los miembros del Poder Legislativo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-173', lawId: 'const-mendoza', number: '173', title: '', originalText: `La ley establecerá la justicia inferior o de paz en toda la Provincia, teniendo en consideración la extensión territorial de cada departamento y su población.`, currentText: `La ley establecerá la justicia inferior o de paz en toda la Provincia, teniendo en consideración la extensión territorial de cada departamento y su población.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-174', lawId: 'const-mendoza', number: '174', title: '', originalText: `Los funcionarios de la justicia inferior o de paz, serán nombrados por el Poder Ejecutivo a propuesta en terna de la Suprema Corte de Justicia y permanecerán en el ejercicio de sus funciones mientras dure su buena conducta.`, currentText: `Los funcionarios de la justicia inferior o de paz, serán nombrados por el Poder Ejecutivo a propuesta en terna de la Suprema Corte de Justicia y permanecerán en el ejercicio de sus funciones mientras dure su buena conducta.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-175', lawId: 'const-mendoza', number: '175', title: '', originalText: `Estos funcionarios podrán ser destituidos o suspendidos por la Suprema Corte, por faltas o delitos en el ejercicio de sus funciones o por cualquier otra causa que comprometa el prestigio de la administración de justicia. Mientras la ley no determine el procedimiento para los casos de acusación ante la Corte, se aplicará en lo que sea pertinente, lo dispuesto en el artículo 165 de esta Constitución, que servirá de base a la ley reglamentaria.`, currentText: `Estos funcionarios podrán ser destituidos o suspendidos por la Suprema Corte, por faltas o delitos en el ejercicio de sus funciones o por cualquier otra causa que comprometa el prestigio de la administración de justicia. Mientras la ley no determine el procedimiento para los casos de acusación ante la Corte, se aplicará en lo que sea pertinente, lo dispuesto en el artículo 165 de esta Constitución, que servirá de base a la ley reglamentaria.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-176', lawId: 'const-mendoza', number: '176', title: '', originalText: `Para ser funcionario de la justicia inferior o de paz, se requiere: 1 - Ciudadanía en ejercicio y un año de residencia para los que no hubieren nacido en la Provincia. 2 - Ser mayor de edad y tener menos de 65 años y las demás condiciones que establezca la ley.`, currentText: `Para ser funcionario de la justicia inferior o de paz, se requiere: 1 - Ciudadanía en ejercicio y un año de residencia para los que no hubieren nacido en la Provincia. 2 - Ser mayor de edad y tener menos de 65 años y las demás condiciones que establezca la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-177', lawId: 'const-mendoza', number: '177', title: '', originalText: `Habrá un fiscal de Estado encargado de defender el patrimonio del fisco, que será parte legítima en los juicios contenciosoadministrativos y en todos aquellos en que se afecten intereses del Estado. Tendrá también personería para demandar ante la Suprema Corte y demás tribunales de la Provincia, la nulidad de toda ley, decreto, contrato o resolución, contrarios a las prescripciones de esta Constitución o que en cualquier forma perjudiquen los intereses fiscales de la Provincia. Será también parte en los procesos que se formen ante el Tribunal de Cuentas de la administración pública, al cual servirá de asesor. Gestionará el cumplimiento de las sentencias en los asuntos en que haya intervenido como parte.`, currentText: `Habrá un fiscal de Estado encargado de defender el patrimonio del fisco, que será parte legítima en los juicios contenciosoadministrativos y en todos aquellos en que se afecten intereses del Estado. Tendrá también personería para demandar ante la Suprema Corte y demás tribunales de la Provincia, la nulidad de toda ley, decreto, contrato o resolución, contrarios a las prescripciones de esta Constitución o que en cualquier forma perjudiquen los intereses fiscales de la Provincia. Será también parte en los procesos que se formen ante el Tribunal de Cuentas de la administración pública, al cual servirá de asesor. Gestionará el cumplimiento de las sentencias en los asuntos en que haya intervenido como parte.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-178', lawId: 'const-mendoza', number: '178', title: '', originalText: `Habrá un solo asesor de Gobierno para todas las reparticiones dependientes del Poder Ejecutivo, con excepción de aquellas que tienen un carácter autónomo por esta Constitución.`, currentText: `Habrá un solo asesor de Gobierno para todas las reparticiones dependientes del Poder Ejecutivo, con excepción de aquellas que tienen un carácter autónomo por esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-179', lawId: 'const-mendoza', number: '179', title: '', originalText: `Para ser fiscal de Estado o asesor de Gobierno se requieren las mismas condiciones que para ser miembro de la Suprema Corte. Este funcionario y el fiscal de Estado no podrá ejercer la profesión de abogado.`, currentText: `Para ser fiscal de Estado o asesor de Gobierno se requieren las mismas condiciones que para ser miembro de la Suprema Corte. Este funcionario y el fiscal de Estado no podrá ejercer la profesión de abogado.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-180', lawId: 'const-mendoza', number: '180', title: '', originalText: `El fiscal de Estado y el asesor de Gobierno serán nombrados por el Poder Ejecutivo con acuerdo del Senado, les será aplicable lo dispuesto en el art. 151 de esta Constitución y serán enjuiciables ante el Jury creado por el artículo 164 de la misma.`, currentText: `El fiscal de Estado y el asesor de Gobierno serán nombrados por el Poder Ejecutivo con acuerdo del Senado, les será aplicable lo dispuesto en el art. 151 de esta Constitución y serán enjuiciables ante el Jury creado por el artículo 164 de la misma.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-181', lawId: 'const-mendoza', number: '181', title: '', originalText: `Habrá un Tribunal de Cuentas con jurisdicción en toda la Provincia y con poder bastante para aprobar o desaprobar la percepción e inversión de caudales públicos hechas por todos los funcionarios, empleados y administradores de la Provincia.`, currentText: `Habrá un Tribunal de Cuentas con jurisdicción en toda la Provincia y con poder bastante para aprobar o desaprobar la percepción e inversión de caudales públicos hechas por todos los funcionarios, empleados y administradores de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-182', lawId: 'const-mendoza', number: '182', title: '', originalText: `Todos los poderes públicos, las municipalidades y cuantos empleados y personas administren caudales de la Provincia u otras corporaciones, estarán obligados a remitir anualmente las cuentas documentadas de los dineros que hubieran invertido o percibido, para su aprobación o desaprobación, debiendo el tribunal pronunciarse sobre ellas en el término de un año desde su presentación, so pena de quedar de hecho aprobadas, sin perjuicio de la responsabilidad de aquél. Sus fallos serán sólo susceptibles de los recursos que esta Constitución y las leyes establezcan para ante la Suprema Corte de la Provincia.`, currentText: `Todos los poderes públicos, las municipalidades y cuantos empleados y personas administren caudales de la Provincia u otras corporaciones, estarán obligados a remitir anualmente las cuentas documentadas de los dineros que hubieran invertido o percibido, para su aprobación o desaprobación, debiendo el tribunal pronunciarse sobre ellas en el término de un año desde su presentación, so pena de quedar de hecho aprobadas, sin perjuicio de la responsabilidad de aquél. Sus fallos serán sólo susceptibles de los recursos que esta Constitución y las leyes establezcan para ante la Suprema Corte de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-183', lawId: 'const-mendoza', number: '183', title: '', originalText: `Los fallos del Tribunal de Cuentas quedarán ejecutoriados 30 días después de su notificación y las acciones a que dieren lugar serán deducidas por el fiscal de Estado, ante quien corresponda.`, currentText: `Los fallos del Tribunal de Cuentas quedarán ejecutoriados 30 días después de su notificación y las acciones a que dieren lugar serán deducidas por el fiscal de Estado, ante quien corresponda.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-184', lawId: 'const-mendoza', number: '184', title: '', originalText: `El Tribunal de Cuentas lo compondrá un presidente letrado que deberá reunir las condiciones que se requieren para ser miembro de la Suprema Corte y por lo menos dos vocales contadores públicos de la matrícula, con ciudadanía en ejercicio que tengan 30 años de edad y menos de 65. Estos funcionarios no podrán ejercer su profesión respectiva.`, currentText: `El Tribunal de Cuentas lo compondrá un presidente letrado que deberá reunir las condiciones que se requieren para ser miembro de la Suprema Corte y por lo menos dos vocales contadores públicos de la matrícula, con ciudadanía en ejercicio que tengan 30 años de edad y menos de 65. Estos funcionarios no podrán ejercer su profesión respectiva.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-185', lawId: 'const-mendoza', number: '185', title: '', originalText: `Los miembros del Tribunal de Cuentas serán nombrados por el Poder Ejecutivo, con acuerdo del Senado, siéndoles aplicable la disposición del artículo 180.`, currentText: `Los miembros del Tribunal de Cuentas serán nombrados por el Poder Ejecutivo, con acuerdo del Senado, siéndoles aplicable la disposición del artículo 180.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-186', lawId: 'const-mendoza', number: '186', title: '', originalText: `El uso del agua del dominio público de la Provincia es un derecho inherente a los predios, a los cuales se concede en la medida y condiciones determinadas por el Código Civil y leyes locales.`, currentText: `El uso del agua del dominio público de la Provincia es un derecho inherente a los predios, a los cuales se concede en la medida y condiciones determinadas por el Código Civil y leyes locales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-187', lawId: 'const-mendoza', number: '187', title: '', originalText: `Las leyes sobre irrigación que dicte la Legislatura, en ningún caso privarán a los interesados de los canales, hijuelas y desagues, de la facultad de elegir sus autoridades y administrar sus respectivas rentas, sin perjuicio del control de las autoridades superiores de irrigación.`, currentText: `Las leyes sobre irrigación que dicte la Legislatura, en ningún caso privarán a los interesados de los canales, hijuelas y desagues, de la facultad de elegir sus autoridades y administrar sus respectivas rentas, sin perjuicio del control de las autoridades superiores de irrigación.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-188', lawId: 'const-mendoza', number: '188', title: '', originalText: `Todos los asuntos que se refieran a la irrigación en la Provincia, que no sean de competencia de la justicia ordinaria, estarán exclusivamente a cargo de un Departamento General de Irrigación compuesto de un superintendente nombrado por el Poder Ejecutivo con acuerdo del Senado, de un consejo compuesto de 5 miembros designados en la misma forma y de las demás autoridades que determine la ley.`, currentText: `Todos los asuntos que se refieran a la irrigación en la Provincia, que no sean de competencia de la justicia ordinaria, estarán exclusivamente a cargo de un Departamento General de Irrigación compuesto de un superintendente nombrado por el Poder Ejecutivo con acuerdo del Senado, de un consejo compuesto de 5 miembros designados en la misma forma y de las demás autoridades que determine la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-189', lawId: 'const-mendoza', number: '189', title: '', originalText: `El superintendente de irrigación y los miembros del consejo durarán 5 años en sus funciones y podrán ser reelectos, debiendo renovarse estos últimos, uno cada año, a cuyo efecto se practicará la primera vez el correspondiente sorteo. Durante dicho término, podrán, sin embargo, ser removidos, en la forma y por el Jury creado por los artículos 164 y 165 de esta Constitución.`, currentText: `El superintendente de irrigación y los miembros del consejo durarán 5 años en sus funciones y podrán ser reelectos, debiendo renovarse estos últimos, uno cada año, a cuyo efecto se practicará la primera vez el correspondiente sorteo. Durante dicho término, podrán, sin embargo, ser removidos, en la forma y por el Jury creado por los artículos 164 y 165 de esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-190', lawId: 'const-mendoza', number: '190', title: '', originalText: `Para ser superintendente de irrigación o miembro del consejo, se requiere: ciudadanía en ejercicio, ser mayor de 30 años y tener 5 de residencia en la Provincia.`, currentText: `Para ser superintendente de irrigación o miembro del consejo, se requiere: ciudadanía en ejercicio, ser mayor de 30 años y tener 5 de residencia en la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-191', lawId: 'const-mendoza', number: '191', title: '', originalText: `La ley sobre irrigación que deberá dictar la Legislatura, reglamentará las atribuciones y deberes del superintendente, del consejo, y demás autoridades del ramo.`, currentText: `La ley sobre irrigación que deberá dictar la Legislatura, reglamentará las atribuciones y deberes del superintendente, del consejo, y demás autoridades del ramo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-192', lawId: 'const-mendoza', number: '192', title: '', originalText: `Las obras fundamentales que proyecte el Poder Ejecutivo, como diques distribuidores y de embalse, grandes canales, etc., deberán ser autorizadas por la ley. Las que proyecte el Departamento de Irrigación necesitarán también sanción legislativa cuando sean de la clase y magnitud determinadas en este artículo.`, currentText: `Las obras fundamentales que proyecte el Poder Ejecutivo, como diques distribuidores y de embalse, grandes canales, etc., deberán ser autorizadas por la ley. Las que proyecte el Departamento de Irrigación necesitarán también sanción legislativa cuando sean de la clase y magnitud determinadas en este artículo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-193', lawId: 'const-mendoza', number: '193', title: '', originalText: `La Ley de Irrigación, al reglamentar el gobierno y administración del agua de los ríos de la Provincia, podrá dar a cada uno de aquéllos su dirección autónoma, sin perjuicio de su dependencia del Departamento General de Irrigación, con arreglo a la misma.`, currentText: `La Ley de Irrigación, al reglamentar el gobierno y administración del agua de los ríos de la Provincia, podrá dar a cada uno de aquéllos su dirección autónoma, sin perjuicio de su dependencia del Departamento General de Irrigación, con arreglo a la misma.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-194', lawId: 'const-mendoza', number: '194', title: '', originalText: `Mientras no se haga el aforo de los ríos de la Provincia y sus afluentes, no podrá acordarse ninguna nueva concesión de agua sin una ley especial e informe previo del Departamento de Irrigación, requiriéndose para su sanción el voto favorable de los dos tercios de los miembros que componen cada Cámara. Una vez efectuado el aforo, las concesiones de agua sólo necesitarán el voto de la mitad más uno de los miembros que componen cada Cámara. Las concesiones que se acuerden, mientras no se realice el aforo, tendrán forzosamente carácter eventual.`, currentText: `Mientras no se haga el aforo de los ríos de la Provincia y sus afluentes, no podrá acordarse ninguna nueva concesión de agua sin una ley especial e informe previo del Departamento de Irrigación, requiriéndose para su sanción el voto favorable de los dos tercios de los miembros que componen cada Cámara. Una vez efectuado el aforo, las concesiones de agua sólo necesitarán el voto de la mitad más uno de los miembros que componen cada Cámara. Las concesiones que se acuerden, mientras no se realice el aforo, tendrán forzosamente carácter eventual.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-195', lawId: 'const-mendoza', number: '195', title: '', originalText: `Una vez practicado el aforo de los ríos y arroyos, así como cada vez que se construyan obras de embalse que permitan un mayor aprovechamiento del agua, el Departamento de Irrigación, previo los estudios del caso, determinará las zonas en que convenga ampliar los cultivos, remitiendo los antecedentes a la Legislatura, para que ésta resuelva por el voto de la mitad más uno de los miembros que componen cada Cámara, si se autoriza o no la extensión de los cultivos.`, currentText: `Una vez practicado el aforo de los ríos y arroyos, así como cada vez que se construyan obras de embalse que permitan un mayor aprovechamiento del agua, el Departamento de Irrigación, previo los estudios del caso, determinará las zonas en que convenga ampliar los cultivos, remitiendo los antecedentes a la Legislatura, para que ésta resuelva por el voto de la mitad más uno de los miembros que componen cada Cámara, si se autoriza o no la extensión de los cultivos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-196', lawId: 'const-mendoza', number: '196', title: '', originalText: `El Departamento de Irrigación sancionará anualmente su presupuesto de gastos y cálculo de recursos.`, currentText: `El Departamento de Irrigación sancionará anualmente su presupuesto de gastos y cálculo de recursos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-197', lawId: 'const-mendoza', number: '197', title: '', originalText: `La administración de los intereses y servicios locales en la capital y cada uno de los departamentos de la Provincia, estará a cargo de una municipalidad, compuesta de un Departamento Ejecutivo y otro Deliberativo, cuyos miembros durarán 4 años en el ejercicio de sus funciones, renovándose el Departamento Deliberativo por mitades cada 2 años. Los integrantes del Departamento Deliberativo serán elegidos directamente por el pueblo de los respectivos municipios, conforme con el sistema establecido para la elección de diputados. *`, currentText: `La administración de los intereses y servicios locales en la capital y cada uno de los departamentos de la Provincia, estará a cargo de una municipalidad, compuesta de un Departamento Ejecutivo y otro Deliberativo, cuyos miembros durarán 4 años en el ejercicio de sus funciones, renovándose el Departamento Deliberativo por mitades cada 2 años. Los integrantes del Departamento Deliberativo serán elegidos directamente por el pueblo de los respectivos municipios, conforme con el sistema establecido para la elección de diputados. *`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-198', lawId: 'const-mendoza', number: '198', title: '', originalText: `Los Intendentes serán elegidos directamente por el pueblo de los respectivos Municipios por simple mayoría de los votos válidos emitidos y podrán ser reelegidos por un sólo período consecutivo. Si han sido reelectos no pueden ser elegidos sino con el intervalo de un período.`, currentText: `Los Intendentes serán elegidos directamente por el pueblo de los respectivos Municipios por simple mayoría de los votos válidos emitidos y podrán ser reelegidos por un sólo período consecutivo. Si han sido reelectos no pueden ser elegidos sino con el intervalo de un período.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-199', lawId: 'const-mendoza', number: '199', title: '', originalText: `La Ley Orgánica de las Municipalidades, deslindará las atribuciones y responsabilidades de cada departamento, confiriéndole las facultades necesarias para que ellos puedan atender eficazmente a todos los intereses y servicios locales, con sujeción a las siguientes bases: 1 - El número de miembros del Departamento Deliberativo no será menor de 10. El intendente es el jefe del Departamento Ejecutivo. Para ejercer tal cargo se requiere ser ciudadano argentino. 2 - Serán electores los que lo sean del Registro Municipal en las condiciones que lo establezca la ley. El Registro de Extranjeros estará a cargo de la municipalidad y se formará como la ley lo determine. 3 - Serán elegibles los ciudadanos y extranjeros mayores de edad, del municipio respectivo, y que sean electores. En los concejos municipales no podrá haber más de dos extranjeros. 4 - Las elecciones se verificarán con el mismo sistema electoral establecido para la elección de diputados a la Legislatura y con la reglamentación especial que determine la Ley Orgánica de Municipalidades. 5 - El cargo de intendente deberá ser rentado y también podrá serlo el de concejal (1). 6 - Las municipalidades tendrán las rentas que determine la Ley Orgánica y en ningún caso podrán dictar ordenanzas creando impuestos ni contribuciones de ninguna clase, salvo respecto de los servicios municipales.`, currentText: `La Ley Orgánica de las Municipalidades, deslindará las atribuciones y responsabilidades de cada departamento, confiriéndole las facultades necesarias para que ellos puedan atender eficazmente a todos los intereses y servicios locales, con sujeción a las siguientes bases: 1 - El número de miembros del Departamento Deliberativo no será menor de 10. El intendente es el jefe del Departamento Ejecutivo. Para ejercer tal cargo se requiere ser ciudadano argentino. 2 - Serán electores los que lo sean del Registro Municipal en las condiciones que lo establezca la ley. El Registro de Extranjeros estará a cargo de la municipalidad y se formará como la ley lo determine. 3 - Serán elegibles los ciudadanos y extranjeros mayores de edad, del municipio respectivo, y que sean electores. En los concejos municipales no podrá haber más de dos extranjeros. 4 - Las elecciones se verificarán con el mismo sistema electoral establecido para la elección de diputados a la Legislatura y con la reglamentación especial que determine la Ley Orgánica de Municipalidades. 5 - El cargo de intendente deberá ser rentado y también podrá serlo el de concejal (1). 6 - Las municipalidades tendrán las rentas que determine la Ley Orgánica y en ningún caso podrán dictar ordenanzas creando impuestos ni contribuciones de ninguna clase, salvo respecto de los servicios municipales.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-200', lawId: 'const-mendoza', number: '200', title: '', originalText: `Son atribuciones inherentes a las municipalidades: 1 - Juzgar de la validez o nulidad de la elección de sus miembros y convocar a los electores del municipio con arreglo a la ley, sin perjuicio de lo que dispongan las leyes nacionales o provinciales sobre la materia 2 - Nombrar los empleados municipales. 3 - Tener a su cargo el ornato y salubridad, los establecimientos de beneficencia que no estén a cargo de sociedades particulares y la vialidad pública, respetando las leyes que dicte la Legislatura sobre la materia. 4 - Votar anualmente su presupuesto de gastos y los recursos para costearlos con arreglo a la ley, administrar sus bienes raíces, examinar y resolver sobre las cuentas del año vencido, remitiéndola inmediatamente al Tribunal de Cuentas de la Provincia. Cuando se trate de enajenar o gravar en cualquier forma los bienes raíces del municipio, se necesitarán dos tercios de votos del total de los miembros del concejo. 5 - Nombrar en los diferentes distritos más poblados de cada municipio, comisiones honorarias para desempeñar las funciones que les sean encomendadas por el concejo y la intendencia. 6 - Dictar todas las ordenanzas y reglamentos, dentro de las atribuciones conferidas por la Constitución y por la Ley Orgánica de Municipalidades.`, currentText: `Son atribuciones inherentes a las municipalidades: 1 - Juzgar de la validez o nulidad de la elección de sus miembros y convocar a los electores del municipio con arreglo a la ley, sin perjuicio de lo que dispongan las leyes nacionales o provinciales sobre la materia 2 - Nombrar los empleados municipales. 3 - Tener a su cargo el ornato y salubridad, los establecimientos de beneficencia que no estén a cargo de sociedades particulares y la vialidad pública, respetando las leyes que dicte la Legislatura sobre la materia. 4 - Votar anualmente su presupuesto de gastos y los recursos para costearlos con arreglo a la ley, administrar sus bienes raíces, examinar y resolver sobre las cuentas del año vencido, remitiéndola inmediatamente al Tribunal de Cuentas de la Provincia. Cuando se trate de enajenar o gravar en cualquier forma los bienes raíces del municipio, se necesitarán dos tercios de votos del total de los miembros del concejo. 5 - Nombrar en los diferentes distritos más poblados de cada municipio, comisiones honorarias para desempeñar las funciones que les sean encomendadas por el concejo y la intendencia. 6 - Dictar todas las ordenanzas y reglamentos, dentro de las atribuciones conferidas por la Constitución y por la Ley Orgánica de Municipalidades.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-201', lawId: 'const-mendoza', number: '201', title: '', originalText: `Toda ordenanza sancionada por el concejo, que no fuere observada por el intendente dentro del término de 5 días de haberse comunicado, se considerará promulgada y se inscribirá en el Registro Municipal. (1) Reformado de acuerdo con la Ley 1350, del 10 de octubre de 1939. En caso de veto por la intendencia, se requerirá el voto de la mayoría absoluta de los miembros que componen el concejo, para insistir en su sanción.`, currentText: `Toda ordenanza sancionada por el concejo, que no fuere observada por el intendente dentro del término de 5 días de haberse comunicado, se considerará promulgada y se inscribirá en el Registro Municipal. (1) Reformado de acuerdo con la Ley 1350, del 10 de octubre de 1939. En caso de veto por la intendencia, se requerirá el voto de la mayoría absoluta de los miembros que componen el concejo, para insistir en su sanción.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-202', lawId: 'const-mendoza', number: '202', title: '', originalText: `Las atribuciones expresadas en los artículos anteriores tienen las siguientes limitaciones: 1 - Dar publicidad por la prensa a todos sus actos, publicando mensualmente el balance de la inversión de sus rentas y uno general a fin de cada año. 2 - La convocatoria de los electores para toda elección municipal, deberá hacerse con 15 días de anticipación, por lo menos, y publicarse suficientemente. 3 - No se podá contraer empréstitos, ni enajenar ni gravar los edificios destinados a servicios públicos municipales, sin autorización previa de la Legislatura. 4 - Siempre que se haga uso del crédito para obras señaladas de mejoramiento o para casos eventuales, se votará una suma anual para el servicio de la deuda, no pudiendo aplicarse los fondos a otro objeto que el indicado. 5 - Las enajenaciones sólo podrán hacerse en remate público anunciado con un mes, por lo menos, de anticipación. 6 - Siempre que hubiere de construirse una obra municipal de cualquier género que fuese, en la que hubieran de invertirse fondos comunales, el concejo nombrará a dos de sus miembros para que en asocio del intendente, la dirijan, dando cuenta del empleo de fondos que se destine a ella. 7 - Las obras públicas y las adquisiciones, deberán efectuarse de conformidad a lo establecido en el art. 37. 8 - El por ciento a invertirse en sueldos de sus empleados deberá ser fijado, en forma general para todas las municipalidades, por la H. Legislatura con el voto de los dos tercios de los componentes de cada Cámara. 9 - No podrá trabarse embargo en los bienes y rentas municipales. Cuando haya sentencia que condene a la municipalidad al pago de alguna deuda, ésta gestionará los recursos para efectuar el pago dentro de los 3 meses, so pena de hacerse efectiva la ejecución.`, currentText: `Las atribuciones expresadas en los artículos anteriores tienen las siguientes limitaciones: 1 - Dar publicidad por la prensa a todos sus actos, publicando mensualmente el balance de la inversión de sus rentas y uno general a fin de cada año. 2 - La convocatoria de los electores para toda elección municipal, deberá hacerse con 15 días de anticipación, por lo menos, y publicarse suficientemente. 3 - No se podá contraer empréstitos, ni enajenar ni gravar los edificios destinados a servicios públicos municipales, sin autorización previa de la Legislatura. 4 - Siempre que se haga uso del crédito para obras señaladas de mejoramiento o para casos eventuales, se votará una suma anual para el servicio de la deuda, no pudiendo aplicarse los fondos a otro objeto que el indicado. 5 - Las enajenaciones sólo podrán hacerse en remate público anunciado con un mes, por lo menos, de anticipación. 6 - Siempre que hubiere de construirse una obra municipal de cualquier género que fuese, en la que hubieran de invertirse fondos comunales, el concejo nombrará a dos de sus miembros para que en asocio del intendente, la dirijan, dando cuenta del empleo de fondos que se destine a ella. 7 - Las obras públicas y las adquisiciones, deberán efectuarse de conformidad a lo establecido en el art. 37. 8 - El por ciento a invertirse en sueldos de sus empleados deberá ser fijado, en forma general para todas las municipalidades, por la H. Legislatura con el voto de los dos tercios de los componentes de cada Cámara. 9 - No podrá trabarse embargo en los bienes y rentas municipales. Cuando haya sentencia que condene a la municipalidad al pago de alguna deuda, ésta gestionará los recursos para efectuar el pago dentro de los 3 meses, so pena de hacerse efectiva la ejecución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-203', lawId: 'const-mendoza', number: '203', title: '', originalText: `Los concejos municipales, los miembros de éstos y los empleados nombrados por ellos, están sujetos a las siguientes responsablidades: 1 - Los cuerpos municipales responden ante los tribunales ordinarios de sus omisiones y de sus transgresiones a la Constitución y a las leyes. 2 - Los miembros de las municipalidades, responden personalmente, no sólo de cualquier acto definido y penado por la ley, sino también de los daños y perjuicios que provengan de la falta de cumplimiento de sus deberes. 3 - Los intendentes municipales y los miembros del concejo pueden ser removidos de sus cargos por mala conducta o abusos en el manejo de los fondos municipales, sin perjuicios de las responsabilidades civiles o criminales en que incurran por estas causas. La remoción sólo podrá ser resuelta por el voto de dos tercios del total de los miembros del concejo.`, currentText: `Los concejos municipales, los miembros de éstos y los empleados nombrados por ellos, están sujetos a las siguientes responsablidades: 1 - Los cuerpos municipales responden ante los tribunales ordinarios de sus omisiones y de sus transgresiones a la Constitución y a las leyes. 2 - Los miembros de las municipalidades, responden personalmente, no sólo de cualquier acto definido y penado por la ley, sino también de los daños y perjuicios que provengan de la falta de cumplimiento de sus deberes. 3 - Los intendentes municipales y los miembros del concejo pueden ser removidos de sus cargos por mala conducta o abusos en el manejo de los fondos municipales, sin perjuicios de las responsabilidades civiles o criminales en que incurran por estas causas. La remoción sólo podrá ser resuelta por el voto de dos tercios del total de los miembros del concejo.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-204', lawId: 'const-mendoza', number: '204', title: '', originalText: `En los casos de acefalía de la intendencia, serán desempeñadas sus funciones por el presidente del concejo. La remoción como intendente no importa la cesantía como concejal, mientras no recaiga resolución en contrario.`, currentText: `En los casos de acefalía de la intendencia, serán desempeñadas sus funciones por el presidente del concejo. La remoción como intendente no importa la cesantía como concejal, mientras no recaiga resolución en contrario.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-205', lawId: 'const-mendoza', number: '205', title: '', originalText: `Todos los actos, resoluciones y contratos emanados de autoridades municipales que no estén constituidas en la forma que prescribe esta Constitución, serán de ningún valor.`, currentText: `Todos los actos, resoluciones y contratos emanados de autoridades municipales que no estén constituidas en la forma que prescribe esta Constitución, serán de ningún valor.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-206', lawId: 'const-mendoza', number: '206', title: '', originalText: `Los conflictos internos de las municipalidades y los de éstas con otras municipalidades o autoridades de la Provincia, serán dirimidos por la Suprema Corte de Justicia. Cualquiera de las partes interesadas podrá ocurrir directamente a la Corte.`, currentText: `Los conflictos internos de las municipalidades y los de éstas con otras municipalidades o autoridades de la Provincia, serán dirimidos por la Suprema Corte de Justicia. Cualquiera de las partes interesadas podrá ocurrir directamente a la Corte.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-207', lawId: 'const-mendoza', number: '207', title: '', originalText: `En caso de acefalía de una municipalidad, el Poder Ejecutivo podrá intervenir al solo objeto de convocar a elecciones dentro del término de 30 días a contar desde el momento en que la municipalidad sea intervenida.`, currentText: `En caso de acefalía de una municipalidad, el Poder Ejecutivo podrá intervenir al solo objeto de convocar a elecciones dentro del término de 30 días a contar desde el momento en que la municipalidad sea intervenida.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-208', lawId: 'const-mendoza', number: '208', title: '', originalText: `La Legislatura de la Provincia podrá aumentar el número de municipalidades, subdividiendo los departamentos, cuando así lo requieran las necesidades de la población, con el voto de la mayoría absoluta de los miembros que componen cada Cámara; pero en ningún caso podrá disminuir el número de departamento existentes al promulgarse esta Constitución.`, currentText: `La Legislatura de la Provincia podrá aumentar el número de municipalidades, subdividiendo los departamentos, cuando así lo requieran las necesidades de la población, con el voto de la mayoría absoluta de los miembros que componen cada Cámara; pero en ningún caso podrá disminuir el número de departamento existentes al promulgarse esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-209', lawId: 'const-mendoza', number: '209', title: '', originalText: `Los poderes que esta Constitución confiere exclusivamente a las municipalidades, no podrán ser limitados por ninguna autoridad de la Provincia.`, currentText: `Los poderes que esta Constitución confiere exclusivamente a las municipalidades, no podrán ser limitados por ninguna autoridad de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-210', lawId: 'const-mendoza', number: '210', title: '', originalText: `Los miembros del concejo municipal son inviolables, por las opiniones que manifiesten y por los votos que emitan en el desempeño de su cargo. Ninguna autoridad podrá reconvenirlos ni procesarlos en ningún tiempo, por tales causas.`, currentText: `Los miembros del concejo municipal son inviolables, por las opiniones que manifiesten y por los votos que emitan en el desempeño de su cargo. Ninguna autoridad podrá reconvenirlos ni procesarlos en ningún tiempo, por tales causas.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-211', lawId: 'const-mendoza', number: '211', title: '', originalText: `La Legislatura dictará las leyes necesarias para establecer y organizar un sistema de educación común, pudiendo también organizar la enseñanza secundaria, superior, normal, industrial y universitaria, cuando lo juzgue conveniente.`, currentText: `La Legislatura dictará las leyes necesarias para establecer y organizar un sistema de educación común, pudiendo también organizar la enseñanza secundaria, superior, normal, industrial y universitaria, cuando lo juzgue conveniente.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-212', lawId: 'const-mendoza', number: '212', title: '', originalText: `Las leyes que organicen y reglamenten la educación deberán sujetarse a las bases siguientes: 1 - La educación será laica, gratuita y obligatoria, en las condiciones y bajo las penas que la ley establezca. 2 - La dirección técnica de las escuelas públicas, la superintendencia, inspección y vigilancia de la enseñanza común y especial, estará a cargo de un director general de la enseñanza, de acuerdo con las reglas que la ley prescribe. El director general será también quien haga cumplir por las familias la obligación en que están los niños de recibir la enseñanza primaria y por las escuelas privadas, las leyes y reglamentos que rigen la higiene escolar. 3 - El director general de escuelas será nombrado por el Poder Ejecutivo con acuerdo del Senado y durará en sus funciones 4 años, pudiendo ser reelecto. 4 - La administración general de las escuelas, en cuanto nos afecte su carácter técnico, estará a cargo de un Consejo Administrativo de la Enseñanza Pública, cuyas funciones reglamentará la ley. 5 - El Consejo General de Educación se compondrá, por lo menos, de cuatro miembros ad honorem, además del director general, nombrados por el Poder Ejecutivo con acuerdo del Senado y se renovarán por mitad cada 2 años, pudiendo ser reelectos. 6 - La renta escolar en ningún caso podrá ser distraída para otro objeto distinto al de su creación. 7 - Es obligatoria la enseñanza del idioma e historia nacional y de las Constituciones nacional y provincial en todo establecimiento de educación, sea de carácter fiscal o particular. 8 - La enseñanza pública y su dirección y administración, será costeada con las rentas propias de la administración escolar y con el 20% de las rentas generales de la Provincia como mínimum y con el producido de las subvenciones nacionales que correspondan. La ley determinará los recursos que se asignen para la formación del tanto por ciento con que debe concurrir la Provincia, prefiriendo los de carácter más permanente. 9 - Las leyes de impuestos escolares serán permanentes y no dejarán de regir mientras no se hayan promulgado otras que las sustituyan o modifiquen. 10 - Ninguna parte de las rentas escolares podrá tener otra aplicación que la de pagar los sueldos y demás gastos de la administración escolar y de las escuelas públicas que se comprendan en el presupuesto del ramo. 11 - Se formará un fondo permanente de las escuelas, depositado a premio en el establecimiento bancario que determine la ley, o en fondos públicos, sin que pueda disponerse más que de sus rentas para subvenir equitativa y concurrentemente con los vecindarios, a la adquisición de terrenos y construcción de edificios para escuelas. La base de este fondo permanente será del 50% del arrendamiento de las tierras públicas y de los demás recursos que a este objeto determine la ley.`, currentText: `Las leyes que organicen y reglamenten la educación deberán sujetarse a las bases siguientes: 1 - La educación será laica, gratuita y obligatoria, en las condiciones y bajo las penas que la ley establezca. 2 - La dirección técnica de las escuelas públicas, la superintendencia, inspección y vigilancia de la enseñanza común y especial, estará a cargo de un director general de la enseñanza, de acuerdo con las reglas que la ley prescribe. El director general será también quien haga cumplir por las familias la obligación en que están los niños de recibir la enseñanza primaria y por las escuelas privadas, las leyes y reglamentos que rigen la higiene escolar. 3 - El director general de escuelas será nombrado por el Poder Ejecutivo con acuerdo del Senado y durará en sus funciones 4 años, pudiendo ser reelecto. 4 - La administración general de las escuelas, en cuanto nos afecte su carácter técnico, estará a cargo de un Consejo Administrativo de la Enseñanza Pública, cuyas funciones reglamentará la ley. 5 - El Consejo General de Educación se compondrá, por lo menos, de cuatro miembros ad honorem, además del director general, nombrados por el Poder Ejecutivo con acuerdo del Senado y se renovarán por mitad cada 2 años, pudiendo ser reelectos. 6 - La renta escolar en ningún caso podrá ser distraída para otro objeto distinto al de su creación. 7 - Es obligatoria la enseñanza del idioma e historia nacional y de las Constituciones nacional y provincial en todo establecimiento de educación, sea de carácter fiscal o particular. 8 - La enseñanza pública y su dirección y administración, será costeada con las rentas propias de la administración escolar y con el 20% de las rentas generales de la Provincia como mínimum y con el producido de las subvenciones nacionales que correspondan. La ley determinará los recursos que se asignen para la formación del tanto por ciento con que debe concurrir la Provincia, prefiriendo los de carácter más permanente. 9 - Las leyes de impuestos escolares serán permanentes y no dejarán de regir mientras no se hayan promulgado otras que las sustituyan o modifiquen. 10 - Ninguna parte de las rentas escolares podrá tener otra aplicación que la de pagar los sueldos y demás gastos de la administración escolar y de las escuelas públicas que se comprendan en el presupuesto del ramo. 11 - Se formará un fondo permanente de las escuelas, depositado a premio en el establecimiento bancario que determine la ley, o en fondos públicos, sin que pueda disponerse más que de sus rentas para subvenir equitativa y concurrentemente con los vecindarios, a la adquisición de terrenos y construcción de edificios para escuelas. La base de este fondo permanente será del 50% del arrendamiento de las tierras públicas y de los demás recursos que a este objeto determine la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-213', lawId: 'const-mendoza', number: '213', title: '', originalText: `Tanto el director general como los miembros del consejo podrán ser acusados por cualquier habitante de la Provincia, por falta o delitos cometidos en el ejercicio de sus funciones ante el Jury establecido por el artículo 164 de esta Constitución.`, currentText: `Tanto el director general como los miembros del consejo podrán ser acusados por cualquier habitante de la Provincia, por falta o delitos cometidos en el ejercicio de sus funciones ante el Jury establecido por el artículo 164 de esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-214', lawId: 'const-mendoza', number: '214', title: '', originalText: `La enseñanza especial deberá referirse principalmente a las industrias agrícolas, fabril y de artes y oficios.`, currentText: `La enseñanza especial deberá referirse principalmente a las industrias agrícolas, fabril y de artes y oficios.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-215', lawId: 'const-mendoza', number: '215', title: '', originalText: `La enseñanza normal propenderá en primer término a la formación de maestras y maestros con aquellas especialidades agrícolas, ganaderas e industriales que puedan aplicarse a las distintas regiones de la Provincia.`, currentText: `La enseñanza normal propenderá en primer término a la formación de maestras y maestros con aquellas especialidades agrícolas, ganaderas e industriales que puedan aplicarse a las distintas regiones de la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-216', lawId: 'const-mendoza', number: '216', title: '', originalText: `Las leyes orgánicas que se dicten en adelante sobre instrucción secundaria y superior, se ajustarán a las reglas siguientes: 1 - La instrucción secundaria y superior estará a cargo de universidades, cuya organización deberá dictarse teniendo por norma la de las universidades nacionales. 2 - La enseñanza secundaria y superior será accesible para todos los habitantes de la Provincia con arreglo a la ley.`, currentText: `Las leyes orgánicas que se dicten en adelante sobre instrucción secundaria y superior, se ajustarán a las reglas siguientes: 1 - La instrucción secundaria y superior estará a cargo de universidades, cuya organización deberá dictarse teniendo por norma la de las universidades nacionales. 2 - La enseñanza secundaria y superior será accesible para todos los habitantes de la Provincia con arreglo a la ley.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-217', lawId: 'const-mendoza', number: '217', title: '', originalText: `No podrá trabarse embargo en los bienes y rentas destinados a la educación. Cuando haya sentencia que condene al consejo al pago de una deuda, éste gestionará los recursos necesarios para efectuar el pago dentro de los 3 meses, so pena de hacerse efectiva la ejecución.`, currentText: `No podrá trabarse embargo en los bienes y rentas destinados a la educación. Cuando haya sentencia que condene al consejo al pago de una deuda, éste gestionará los recursos necesarios para efectuar el pago dentro de los 3 meses, so pena de hacerse efectiva la ejecución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-218', lawId: 'const-mendoza', number: '218', title: '', originalText: `Mientras el Banco de la Provincia de Mendoza subsista como Banco del Estado y no se transforme en una institución en la cual la Provincia sea accionista, se regirá por una ley orgánica cuyas bases fundamentales serán las siguientes: 1 - El Banco conservará los privilegios, garantías y excepciones que le estén acordados por las leyes vigentes al promulgarse esta Constitución. 2 - La Provincia de Mendoza garante las operaciones del Banco, y todas las obligaciones a favor y en contra de éste se considerarán de aquélla. 3 - El Banco podrá realizar todas las operaciones que por su naturaleza pertenezcan al giro ordinario de los establecimientos bancarios y que no estén prohibidas por leyes generales de la Nación o de la Provincia. 4 - El gobierno y administración general del Banco estarán a cargo de un directorio compuesto de seis miembros y un director gerente nombrado por el Poder Ejecutivo con acuerdo del Senado. Los directores durarán 4 años en el ejercicio de sus cargos y se renovarán por mitad cada 2 años, pudiendo ser reelectos. 5 - El director gerente será a la vez presidente del directorio con voz y voto en sus deliberaciones, durará 5 años en el ejercicio de sus funciones y podrá ser reelecto. 6 - El directorio tendrá todas las atribuciones que sean propias a este género de instituciones y que determine la ley. 7 - El director gerente y los directores que con su voto concurriesen a la realización de operaciones o actos contrarios a las disposiciones de las leyes, decretos y reglamentos que rijan al Banco, serán personalmente responsables de los perjuicios que ocasionen, siendo enjuiciables ante el Jury creado por el artículo 164 de esta Constitución. 8 - El director gerente deberá ser ciudadano argentino, mayor de 30 años y menor de 70. 9 - En el directorio podrá haber hasta dos extranjeros, siempre que tengan 5 años de residencia inmediata en la Provincia.`, currentText: `Mientras el Banco de la Provincia de Mendoza subsista como Banco del Estado y no se transforme en una institución en la cual la Provincia sea accionista, se regirá por una ley orgánica cuyas bases fundamentales serán las siguientes: 1 - El Banco conservará los privilegios, garantías y excepciones que le estén acordados por las leyes vigentes al promulgarse esta Constitución. 2 - La Provincia de Mendoza garante las operaciones del Banco, y todas las obligaciones a favor y en contra de éste se considerarán de aquélla. 3 - El Banco podrá realizar todas las operaciones que por su naturaleza pertenezcan al giro ordinario de los establecimientos bancarios y que no estén prohibidas por leyes generales de la Nación o de la Provincia. 4 - El gobierno y administración general del Banco estarán a cargo de un directorio compuesto de seis miembros y un director gerente nombrado por el Poder Ejecutivo con acuerdo del Senado. Los directores durarán 4 años en el ejercicio de sus cargos y se renovarán por mitad cada 2 años, pudiendo ser reelectos. 5 - El director gerente será a la vez presidente del directorio con voz y voto en sus deliberaciones, durará 5 años en el ejercicio de sus funciones y podrá ser reelecto. 6 - El directorio tendrá todas las atribuciones que sean propias a este género de instituciones y que determine la ley. 7 - El director gerente y los directores que con su voto concurriesen a la realización de operaciones o actos contrarios a las disposiciones de las leyes, decretos y reglamentos que rijan al Banco, serán personalmente responsables de los perjuicios que ocasionen, siendo enjuiciables ante el Jury creado por el artículo 164 de esta Constitución. 8 - El director gerente deberá ser ciudadano argentino, mayor de 30 años y menor de 70. 9 - En el directorio podrá haber hasta dos extranjeros, siempre que tengan 5 años de residencia inmediata en la Provincia.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-219', lawId: 'const-mendoza', number: '219', title: '', originalText: `Esta Constitución podrá ser reformada en cualquier tiempo, total o parcialmente, en la forma que ella misma determina.`, currentText: `Esta Constitución podrá ser reformada en cualquier tiempo, total o parcialmente, en la forma que ella misma determina.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-220', lawId: 'const-mendoza', number: '220', title: '', originalText: `Podrá promoverse la reforma en cualquiera de las dos Cámaras o por iniciativa del Poder Ejecutivo, pero la ley que declare la necesidad de la reforma deberá ser sancionada por dos tercios de los miembros que componen cada Cámara y no podrá ser vetada.`, currentText: `Podrá promoverse la reforma en cualquiera de las dos Cámaras o por iniciativa del Poder Ejecutivo, pero la ley que declare la necesidad de la reforma deberá ser sancionada por dos tercios de los miembros que componen cada Cámara y no podrá ser vetada.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-221', lawId: 'const-mendoza', number: '221', title: '', originalText: `Declarada por la Legislatura la necesidad de la reforma total o parcial de la Constitución, se someterá al pueblo para que en la próxima elección de diputados, se vote en todas las secciones electorales en pro o en contra de la convocatoria de una Convención Constituyente. Si la mayoría de los electores de la Provincia votase afirmativamente, el Poder Ejecutivo convocará a una Convención que se compondrá de tantos miembros cuantos sean los que componen la Legislatura. Los convencionales serán elegidos en la misma forma que los diputados.`, currentText: `Declarada por la Legislatura la necesidad de la reforma total o parcial de la Constitución, se someterá al pueblo para que en la próxima elección de diputados, se vote en todas las secciones electorales en pro o en contra de la convocatoria de una Convención Constituyente. Si la mayoría de los electores de la Provincia votase afirmativamente, el Poder Ejecutivo convocará a una Convención que se compondrá de tantos miembros cuantos sean los que componen la Legislatura. Los convencionales serán elegidos en la misma forma que los diputados.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-222', lawId: 'const-mendoza', number: '222', title: '', originalText: `La Convención se reunirá 10 días después que la Junta Electoral de la Provincia haya practicado el escrutinio y otorgado el diploma provisorio a los convencionales electos, a fin de pronunciar el juicio definitivo sobre las elecciones. Una vez constituida la Convención procederá a llenar su cometido dentro del término de un año, vencido el cual caducará su mandato.`, currentText: `La Convención se reunirá 10 días después que la Junta Electoral de la Provincia haya practicado el escrutinio y otorgado el diploma provisorio a los convencionales electos, a fin de pronunciar el juicio definitivo sobre las elecciones. Una vez constituida la Convención procederá a llenar su cometido dentro del término de un año, vencido el cual caducará su mandato.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-223', lawId: 'const-mendoza', number: '223', title: '', originalText: `La necesidad de enmienda o de reforma de un solo artículo de esta Constitución, podrá ser declarada y sancionada también por dos tercios de los miembros que componen cada Cámara. Una vez dictada la ley que sancione la enmienda o reforma, se someterá al pueblo para que en la próxima elección de diputados se vote en todas las secciones electorales, en pro o en contra de la reforma sancionada. Si la mayoría de los electores de la Provincia votase afirmativamente, la enmienda quedará aprobada por el pueblo y deberá ser promulgada por el Poder Ejecutivo e incorporada al texto de esta Constitución.`, currentText: `La necesidad de enmienda o de reforma de un solo artículo de esta Constitución, podrá ser declarada y sancionada también por dos tercios de los miembros que componen cada Cámara. Una vez dictada la ley que sancione la enmienda o reforma, se someterá al pueblo para que en la próxima elección de diputados se vote en todas las secciones electorales, en pro o en contra de la reforma sancionada. Si la mayoría de los electores de la Provincia votase afirmativamente, la enmienda quedará aprobada por el pueblo y deberá ser promulgada por el Poder Ejecutivo e incorporada al texto de esta Constitución.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-224', lawId: 'const-mendoza', number: '224', title: '', originalText: `Las reformas de la Constitución, a que se refiere el artículo anterior, no podrá votarse por la Legislatura, sino con un intervalo de un año por lo menos.`, currentText: `Las reformas de la Constitución, a que se refiere el artículo anterior, no podrá votarse por la Legislatura, sino con un intervalo de un año por lo menos.`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
  { id: 'const-mendoza-art-225', lawId: 'const-mendoza', number: '225', title: '', originalText: `Para ser convencional se requieren las mismas calidades que para ser diputado a la Legislatura, no pudiendo ser electo el gobernador de la Provincia. No podrán ser convencionales más de 10 ciudadanos naturalizados, y en caso de ser electo mayor número, se eliminarán por sorteo que deberá efectuar la Junta Electoral. Los convencionales gozarán de las mismas inmunidades que los miembros de la Legislatura. Firmantes FIRMANTES`, currentText: `Para ser convencional se requieren las mismas calidades que para ser diputado a la Legislatura, no pudiendo ser electo el gobernador de la Provincia. No podrán ser convencionales más de 10 ciudadanos naturalizados, y en caso de ser electo mayor número, se eliminarán por sorteo que deberá efectuar la Junta Electoral. Los convencionales gozarán de las mismas inmunidades que los miembros de la Legislatura. Firmantes FIRMANTES`, plainLanguageExplanation: '', practicalEffects: [], examples: [], relatedArticles: [], jurisprudence: [], regulations: [], keywords: [], order: 0, segments: [], amendments: [] },
];



